{
  "name": "WealthFlow Dashboard",
  "description": "A comprehensive personal finance management tool featuring real-time earning/spending rates, balance sheets, P&L accounts, and multi-account tracking for banks, credit cards, and wallets."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  isBoarded: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number; // Current outstanding
  last4: string;
  limit?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity; // For recurring expenses
}

export interface Asset {
  id: string;
  name: string;
  value: number;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability } from '../types';

interface FinanceContextType {
  state: FinancialState;
  updateProfile: (profile: UserProfile) => void;
  addBank: (bank: BankAccount) => void;
  addCard: (card: CreditCard) => void;
  addWallet: (wallet: Wallet) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  resetBoarding: () => void;
}

const STORAGE_KEY = 'wealthflow_state';

const initialState: FinancialState = {
  profile: { name: '', designation: '', age: 0, city: '', isBoarded: false },
  banks: [],
  cards: [],
  wallets: [],
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<FinancialState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : initialState;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateProfile = (profile: UserProfile) => setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...prev.banks, bank],
    assets: [...prev.assets, { id: `auto-asset-bank-${bank.id}`, name: `Cash in ${bank.name}`, value: bank.balance }]
  }));

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...prev.cards, card],
    liabilities: [...prev.liabilities, { id: `auto-liab-card-${card.id}`, name: `Credit Card: ${card.lenderName}`, amount: card.balance }]
  }));

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...prev.wallets, wallet],
    assets: [...prev.assets, { id: `auto-asset-wallet-${wallet.id}`, name: `Wallet: ${wallet.name}`, value: wallet.balance }]
  }));

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...prev.assets, asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...prev.liabilities, liability] }));

  const resetBoarding = () => setState(initialState);

  return (
    <FinanceContext.Provider value={{ 
      state, updateProfile, addBank, addCard, addWallet, 
      addIncome, addExpense, addAsset, addLiability, resetBoarding 
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import { FinancialState, Periodicity } from '../types';

const periodicityMultiplier = (p: Periodicity): number => {
  switch (p) {
    case 'Daily': return 1;
    case 'Weekly': return 1 / 7;
    case 'Monthly': return 1 / 30;
    case 'Yearly': return 1 / 365;
    default: return 0;
  }
};

export const calculateRates = (state: FinancialState) => {
  const dailyIncome = state.incomes.reduce((acc, inc) => {
    const multiplier = periodicityMultiplier(inc.periodicity);
    // Periodicity logic: if weekly, daily = amount / 7. If daily, daily = amount.
    // Wait, the multiplier should be how many of those periods happen in a day.
    // Daily = 1, Weekly = 1/7, Monthly = 1/30.
    return acc + (inc.amount * multiplier);
  }, 0);

  const dailyExpense = state.expenses.reduce((acc, exp) => {
    // If expense doesn't have periodicity, assume it's a one-off categorized daily for this metric if date is today?
    // User wants a 'rate'. Let's assume recurring expenses or averaged monthly.
    const multiplier = periodicityMultiplier(exp.periodicity || 'Monthly');
    return acc + (exp.amount * multiplier);
  }, 0);

  return {
    earningsPerHour: dailyIncome / 24,
    spendingPerHour: dailyExpense / 24,
  };
};

export const calculateNetWorth = (state: FinancialState) => {
  const totalAssets = state.assets.reduce((acc, a) => acc + a.value, 0);
  const totalLiabilities = state.liabilities.reduce((acc, l) => acc + l.amount, 0);
  return {
    assets: totalAssets,
    liabilities: totalLiabilities,
    netWorth: totalAssets - totalLiabilities
  };
};

import React from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, resetBoarding } = useFinance();

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'statements', label: 'Balance Sheet & P&L', icon: '📑' },
    { id: 'profile', label: 'Profile', icon: '👤' },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-white border-r border-slate-200 shadow-sm z-10">
        <div className="p-6">
          <h1 className="text-2xl font-bold text-indigo-600 flex items-center gap-2">
            <span className="text-3xl">💎</span> WealthFlow
          </h1>
        </div>
        <nav className="mt-4 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
                activeTab === item.id 
                  ? 'bg-indigo-50 text-indigo-700' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <span>{item.icon}</span>
              {item.label}
            </button>
          ))}
          <button
            onClick={resetBoarding}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium text-rose-600 hover:bg-rose-50 transition-colors mt-8"
          >
            <span>🔄</span> Reset Data
          </button>
        </nav>

        <div className="absolute bottom-0 w-64 p-4 border-t border-slate-100 bg-white">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold">
              {state.profile.name.charAt(0)}
            </div>
            <div>
              <p className="text-sm font-semibold text-slate-800 truncate">{state.profile.name}</p>
              <p className="text-xs text-slate-500 truncate">{state.profile.designation}</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen relative">
        <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-4 z-20 flex justify-between items-center">
          <h2 className="text-xl font-semibold text-slate-800 capitalize">
            {activeTab.replace('-', ' ')}
          </h2>
          <div className="flex items-center gap-4">
             <span className="text-xs font-medium text-slate-400 uppercase tracking-widest">Live Updates</span>
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
          </div>
        </header>
        <div className="p-8 max-w-7xl mx-auto pb-24">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth } from '../utils/calculations';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

const Dashboard: React.FC = () => {
  const { state } = useFinance();
  const rates = calculateRates(state);
  const netWorthData = calculateNetWorth(state);

  const stats = [
    { label: 'Earnings / Hour', value: `$${rates.earningsPerHour.toFixed(2)}`, trend: 'up', color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Spending / Hour', value: `$${rates.spendingPerHour.toFixed(2)}`, trend: 'down', color: 'text-rose-600', bg: 'bg-rose-50' },
    { label: 'Total Investments', value: `$${netWorthData.assets.toLocaleString()}`, trend: 'neutral', color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Net Worth', value: `$${netWorthData.netWorth.toLocaleString()}`, trend: 'up', color: 'text-indigo-600', bg: 'bg-indigo-50' },
  ];

  const barData = [
    { name: 'Income', amount: rates.earningsPerHour * 24 },
    { name: 'Expense', amount: rates.spendingPerHour * 24 },
  ];

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#10b981' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#f43f5e' },
  ];

  return (
    <div className="space-y-8">
      {/* Metrics Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition-all hover:shadow-md">
            <p className="text-sm font-medium text-slate-500 mb-1">{stat.label}</p>
            <div className="flex items-baseline gap-2">
               <h3 className={`text-2xl font-bold ${stat.color}`}>{stat.value}</h3>
               <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">/ 24h cycle</span>
            </div>
            <div className={`mt-4 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${stat.bg} ${stat.color}`}>
              {stat.trend === 'up' ? '▲' : stat.trend === 'down' ? '▼' : '●'} Stable
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Daily Cashflow Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Daily Projected Cashflow</h4>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={barData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="amount" radius={[8, 8, 0, 0]} barSize={60}>
                  {barData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index === 0 ? '#10b981' : '#f43f5e'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Assets vs Liabilities Pie */}
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Balance Distribution</h4>
          <div className="h-72 flex flex-col items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="mt-4 w-full space-y-2">
               <div className="flex justify-between items-center text-sm">
                 <span className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-emerald-500"></div> Assets</span>
                 <span className="font-semibold text-slate-700">${netWorthData.assets.toLocaleString()}</span>
               </div>
               <div className="flex justify-between items-center text-sm">
                 <span className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-rose-500"></div> Liabilities</span>
                 <span className="font-semibold text-slate-700">${netWorthData.liabilities.toLocaleString()}</span>
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Recent Accounts Summary */}
      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <h4 className="text-lg font-semibold text-slate-800 mb-6">Linked Liquidity</h4>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="p-4 bg-slate-50 rounded-xl">
             <p className="text-xs text-slate-500 font-bold uppercase mb-2">Banks</p>
             <p className="text-xl font-bold text-slate-800">
               ${state.banks.reduce((acc, b) => acc + b.balance, 0).toLocaleString()}
             </p>
             <p className="text-xs text-slate-400 mt-1">{state.banks.length} accounts</p>
          </div>
          <div className="p-4 bg-slate-50 rounded-xl">
             <p className="text-xs text-slate-500 font-bold uppercase mb-2">Wallets</p>
             <p className="text-xl font-bold text-slate-800">
               ${state.wallets.reduce((acc, w) => acc + w.balance, 0).toLocaleString()}
             </p>
             <p className="text-xs text-slate-400 mt-1">{state.wallets.length} active wallets</p>
          </div>
          <div className="p-4 bg-slate-50 rounded-xl">
             <p className="text-xs text-slate-500 font-bold uppercase mb-2">Available Credit</p>
             <p className="text-xl font-bold text-slate-800">
               ${state.cards.reduce((acc, c) => acc + (c.limit || 0), 0).toLocaleString()}
             </p>
             <p className="text-xs text-slate-400 mt-1">{state.cards.length} cards</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { BankAccount, CreditCard, Wallet } from '../types';

const Accounts: React.FC = () => {
  const { state, addBank, addCard, addWallet } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);

  return (
    <div className="space-y-12">
      {/* Banks Section */}
      <section>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-800">Bank Accounts</h3>
          <button 
            onClick={() => setShowModal('bank')}
            className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors"
          >
            + Add Bank
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {state.banks.map(bank => (
            <div key={bank.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-indigo-50 rounded-xl text-xl">🏦</div>
                <div className="text-right">
                  <p className="text-xs text-slate-400 font-bold uppercase">Balance</p>
                  <p className="text-lg font-bold text-slate-800">${bank.balance.toLocaleString()}</p>
                </div>
              </div>
              <h4 className="font-bold text-slate-800">{bank.name}</h4>
              <p className="text-sm text-slate-500">{bank.accountNumber || 'Checking Account'}</p>
            </div>
          ))}
          {state.banks.length === 0 && <p className="text-slate-400 text-sm col-span-full italic">No bank accounts linked yet.</p>}
        </div>
      </section>

      {/* Credit Cards Section */}
      <section>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-800">Credit Cards</h3>
          <button 
            onClick={() => setShowModal('card')}
            className="px-4 py-2 bg-slate-800 text-white rounded-lg text-sm font-medium hover:bg-slate-900 transition-colors"
          >
            + Add Card
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {state.cards.map(card => (
            <div key={card.id} className="relative overflow-hidden bg-gradient-to-br from-slate-800 to-slate-900 p-8 rounded-2xl text-white shadow-xl">
              <div className="relative z-10 flex flex-col h-full justify-between">
                <div className="flex justify-between items-start">
                  <div>
                    <p className="text-xs opacity-60 font-bold uppercase tracking-widest">Outstanding</p>
                    <p className="text-3xl font-bold">${card.balance.toLocaleString()}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-medium">{card.lenderName}</p>
                    <div className="mt-1 flex gap-1 justify-end">
                      {card.offers.movie && <span title="Movie Offers" className="text-xs">🎬</span>}
                      {card.offers.dining && <span title="Dining Offers" className="text-xs">🍴</span>}
                      {card.offers.lounge && <span title="Lounge Access" className="text-xs">🛋️</span>}
                    </div>
                  </div>
                </div>
                <div className="mt-8 flex justify-between items-end">
                  <p className="font-mono tracking-widest opacity-80">**** **** **** {card.last4}</p>
                  {card.limit && (
                    <div className="text-right">
                      <p className="text-[10px] opacity-40 uppercase">Limit</p>
                      <p className="text-xs font-bold">${card.limit.toLocaleString()}</p>
                    </div>
                  )}
                </div>
              </div>
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>
            </div>
          ))}
          {state.cards.length === 0 && <p className="text-slate-400 text-sm col-span-full italic">No credit cards added.</p>}
        </div>
      </section>

      {/* Wallets Section */}
      <section>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-800">Wallets & Cash</h3>
          <button 
            onClick={() => setShowModal('wallet')}
            className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors"
          >
            + Add Wallet
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {state.wallets.map(wallet => (
            <div key={wallet.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex items-center gap-4">
              <div className="w-10 h-10 rounded-lg bg-orange-50 text-orange-600 flex items-center justify-center text-xl">
                📱
              </div>
              <div>
                <h4 className="text-sm font-bold text-slate-800">{wallet.name}</h4>
                <p className="text-lg font-bold text-indigo-600">${wallet.balance.toLocaleString()}</p>
              </div>
            </div>
          ))}
          {state.wallets.length === 0 && <p className="text-slate-400 text-sm col-span-full italic">No wallet balances recorded.</p>}
        </div>
      </section>

      {/* Modals */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-slate-900 mb-6">Add New {showModal}</h3>
            <AccountForm type={showModal} onCancel={() => setShowModal(null)} />
          </div>
        </div>
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', onCancel: () => void }> = ({ type, onCancel }) => {
  const { addBank, addCard, addWallet } = useFinance();
  const [formData, setFormData] = useState<any>({
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Math.random().toString(36).substr(2, 9);
    if (type === 'bank') {
      addBank({ id, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance) });
    } else if (type === 'card') {
      addCard({ 
        id, 
        lenderName: formData.lender, 
        balance: Number(formData.balance), 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined,
        offers: formData.offers
      });
    } else if (type === 'wallet') {
      addWallet({ id, name: formData.name, balance: Number(formData.balance) });
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {type === 'bank' && (
        <>
          <input required placeholder="Bank Name" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" onChange={e => setFormData({...formData, name: e.target.value})} />
          <input placeholder="Account Number (Optional)" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none" onChange={e => setFormData({...formData, accNum: e.target.value})} />
