import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction } from '../types';

interface FinanceContextType {
  state: FinancialState;
  updateProfile: (profile: UserProfile) => void;
  addBank: (bank: BankAccount) => void;
  addCard: (card: CreditCard) => void;
  addWallet: (wallet: Wallet) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  resetBoarding: () => void;
}

const STORAGE_KEY = 'wealthflow_state';

const initialState: FinancialState = {
  profile: { name: '', designation: '', age: 0, city: '', isBoarded: false },
  banks: [],
  cards: [],
  wallets: [],
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<FinancialState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.transactions) parsed.transactions = [];
      return parsed;
    }
    return initialState;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateProfile = (profile: UserProfile) => setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...prev.banks, bank],
    assets: [...prev.assets, { id: `auto-asset-bank-${bank.id}`, name: `Cash in ${bank.name}`, value: bank.balance }]
  }));

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...prev.cards, card],
    liabilities: [...prev.liabilities, { id: `auto-liab-card-${card.id}`, name: `Credit Card: ${card.lenderName}`, amount: card.balance }]
  }));

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...prev.wallets, wallet],
    assets: [...prev.assets, { id: `auto-asset-wallet-${wallet.id}`, name: `Wallet: ${wallet.name}`, value: wallet.balance }]
  }));

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...prev.assets, asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...prev.liabilities, liability] }));

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...prev.transactions] };

      const updateBalance = (amount: number, isAdding: boolean) => {
        const delta = isAdding ? amount : -amount;

        if (transaction.accountType === 'bank') {
          newState.banks = prev.banks.map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + delta } : b);
        } else if (transaction.accountType === 'card') {
          newState.cards = prev.cards.map(c => c.id === transaction.accountId ? { ...c, balance: c.balance - delta } : c);
        } else if (transaction.accountType === 'wallet') {
          newState.wallets = prev.wallets.map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + delta } : w);
        }
      };

      switch (transaction.type) {
        case 'Income':
          updateBalance(transaction.amount, true);
          newState.incomes = [...prev.incomes, {
            id: transaction.id,
            name: transaction.description,
            amount: transaction.amount,
            periodicity: 'Monthly',
            dateOfReceipt: transaction.date
          }];
          break;
        case 'Expense':
          updateBalance(transaction.amount, false);
          newState.expenses = [...prev.expenses, {
            id: transaction.id,
            category: transaction.category || 'Others',
            amount: transaction.amount,
            date: transaction.date
          }];
          break;
        case 'Asset':
          updateBalance(transaction.amount, false);
          newState.assets = [...prev.assets, {
            id: transaction.id,
            name: transaction.description,
            value: transaction.amount
          }];
          break;
        case 'Liability':
          updateBalance(transaction.amount, true);
          newState.liabilities = [...prev.liabilities, {
            id: transaction.id,
            name: transaction.description,
            amount: transaction.amount
          }];
          break;
      }

      return newState;
    });
  };

  const resetBoarding = () => setState(initialState);

  return (
    <FinanceContext.Provider value={{ 
      state, updateProfile, addBank, addCard, addWallet, 
      addIncome, addExpense, addAsset, addLiability,
      addTransaction, resetBoarding 
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

