const Dashboard: React.FC = () => {
  const { state } = useFinance();
  const rates = calculateRates(state);
  const netWorthData = calculateNetWorth(state);
  const currency = state.profile.currency;

  const stats = [
    { label: 'Earnings / Hour', value: formatCurrency(rates.earningsPerHour, currency), trend: 'up', color: 'text-emerald-600', bg: 'bg-emerald-50', showCycle: true },
    { label: 'Spending / Hour', value: formatCurrency(rates.spendingPerHour, currency), trend: 'down', color: 'text-rose-600', bg: 'bg-rose-50', showCycle: true },
    { label: 'Total Investments', value: formatCurrency(netWorthData.assets, currency), trend: 'neutral', color: 'text-blue-600', bg: 'bg-blue-50', showCycle: false },
    { label: 'Net Worth', value: formatCurrency(netWorthData.netWorth, currency), trend: 'up', color: 'text-indigo-600', bg: 'bg-indigo-50', showCycle: false },
  ];

  const barData = [
    { name: 'Income (MTD)', amount: rates.earningsPerHour * 24 }, 
    { name: 'Expense (MTD)', amount: rates.spendingPerHour * 24 },
  ];

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#10b981' },
