                 <span className="font-semibold text-slate-700">{formatCurrency(netWorthData.liabilities, currency)}</span>
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Recent Accounts Summary */}
      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <h4 className="text-lg font-semibold text-slate-800 mb-6">Linked Liquidity</h4>
