    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setFormData(prev => ({ ...prev, type }));
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    addTransaction({
      id: Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: formData.type === 'Expense' ? formData.category : undefined
    });

    setShowModal(false);
    setFormData({ ...formData, amount: '', description: '' });
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal('Income')}
            className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">💰</span> Income
          </button>
          <button 
            onClick={() => handleOpenModal('Expense')}
            className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">📉</span> Expense
          </button>
          <button 
            onClick={() => handleOpenModal('Asset')}
            className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">🏗️</span> Asset
          </button>
          <button 
            onClick={() => handleOpenModal('Liability')}
            className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">🧾</span> Liability
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4">
                      <p className="text-sm font-semibold text-slate-600">{t.date}</p>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm font-bold text-slate-800">{t.description}</p>
                      {t.category && (
                        <span className="text-[10px] text-slate-400 font-bold tracking-tight">
                          {t.category}
                        </span>
                      )}
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>
                        {t.type}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${
                      t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'
                    }`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-16 text-center">
                    <div className="flex flex-col items-center gap-2 opacity-40">
                      <span className="text-4xl">📂</span>
                      <p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">Record {formData.type}</h3>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                 formData.type === 'Income' ? 'bg-emerald-100 text-emerald-700' :
                 formData.type === 'Expense' ? 'bg-rose-100 text-rose-700' :
                 formData.type === 'Asset' ? 'bg-blue-100 text-blue-700' :
                 'bg-amber-100 text-amber-700'
              }`}>
                Entry Mode
              </span>
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select 
                  required
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                  value={formData.accountId}
                  onChange={e => setFormData({ ...formData, accountId: e.target.value })}
                >
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => (
                    <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Amount ({currency})</label>
                  <input 
                    required 
                    type="number" 
                    placeholder="0.00" 
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800"
                    value={formData.amount}
                    onChange={e => setFormData({ ...formData, amount: e.target.value })}
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input 
                    required 
                    type="date" 
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                    value={formData.date}
                    onChange={e => setFormData({ ...formData, date: e.target.value })}
                  />
                </div>
              </div>

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select 
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
                    value={formData.category}
                    onChange={e => setFormData({ ...formData, category: e.target.value })}
                  >
                    <option>Grocery</option>
                    <option>Rent</option>
                    <option>Electricity</option>
                    <option>Commute</option>
                    <option>Dining Out</option>
                    <option>Entertainment</option>
                    <option>Health</option>
                    <option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input 
                  required 
                  placeholder="What was this for?" 
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
                  value={formData.description}
                  onChange={e => setFormData({ ...formData, description: e.target.value })}
                />
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)} 
                  className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors"
                >
                  Discard
                </button>
                <button 
                  type="submit" 
                  className={`flex-1 px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}
                >
                  Save Entry
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';

const countries = [
  { name: 'United States', currency: 'USD' },
  { name: 'India', currency: 'INR' },
  { name: 'United Kingdom', currency: 'GBP' },
  { name: 'European Union', currency: 'EUR' },
  { name: 'Canada', currency: 'CAD' },
  { name: 'Australia', currency: 'AUD' },
  { name: 'Japan', currency: 'JPY' },
  { name: 'Singapore', currency: 'SGD' },
  { name: 'United Arab Emirates', currency: 'AED' },
  { name: 'Saudi Arabia', currency: 'SAR' },
];

const Onboarding: React.FC = () => {
  const { updateProfile, addAsset, addLiability, addBank, addCard, addWallet } = useFinance();
  const [authState, setAuthState] = useState<'LOGIN' | 'OTP' | 'VERIFIED'>('LOGIN');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<any>({
    name: '', designation: '', age: '', city: '',
    country: countries[0].name,
    currency: countries[0].currency,
    // Bank
    bankName: '', bankAccNum: '', bankBalance: '',
    // Card
    cardLender: '', cardBalance: '', cardLast4: '', cardLimit: '', cardOffers: { movie: false, dining: false, concierge: false, lounge: false },
    // Wallet
    walletName: '', walletBalance: '',
    // Asset/Liability
    itemName: '', itemValue: '', itemType: 'Asset'
  });

  const handleCountryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const country = countries.find(c => c.name === e.target.value);
    setFormData({
      ...formData,
      country: e.target.value,
      currency: country ? country.currency : 'USD'
    });
  };

  const handleSendOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 10) {
      setAuthState('OTP');
    }
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(digit => digit !== '')) {
      setAuthState('VERIFIED');
    }
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto focus next input
    if (value !== '' && index < 3) {
      const nextInput = document.getElementById(`otp-${index + 1}`);
      nextInput?.focus();
    }
  };

  const handleComplete = () => {
    updateProfile({
      name: formData.name,
      designation: formData.designation,
      age: Number(formData.age),
      city: formData.city,
      country: formData.country,
      currency: formData.currency,
      isBoarded: true
    });
  };

  const nextStep = () => setStep(s => s + 1);

  if (authState === 'LOGIN') {
    return (
      <div className="min-h-screen bg-indigo-600 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden p-10 animate-in fade-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="inline-block p-4 bg-indigo-50 rounded-2xl text-4xl mb-4">💎</div>
            <h2 className="text-2xl font-bold text-slate-900">Welcome to WealthFlow</h2>
            <p className="text-slate-500 text-sm mt-2">Secure your financial journey with a mobile login.</p>
          </div>
          <form onSubmit={handleSendOtp} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Mobile Number</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">+</span>
                <input 
                  required
                  type="tel"
                  placeholder="Enter 10 digit number"
                  className="w-full p-4 pl-8 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-medium text-slate-800"
                  value={mobileNumber}
                  onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))}
                />
              </div>
            </div>
            <button 
              type="submit"
              disabled={mobileNumber.length < 10}
              className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-50 disabled:shadow-none hover:bg-indigo-700 transition-all"
            >
              Get Verification Code
            </button>
          </form>
          <p className="text-center text-[10px] text-slate-400 mt-8">By continuing, you agree to WealthFlow's Terms and Privacy Policy.</p>
        </div>
      </div>
    );
  }

  if (authState === 'OTP') {
    return (
      <div className="min-h-screen bg-indigo-600 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden p-10 animate-in fade-in slide-in-from-right-8 duration-300">
          <button onClick={() => setAuthState('LOGIN')} className="text-slate-400 hover:text-indigo-600 text-sm font-bold flex items-center gap-2 mb-6">
            <span>←</span> Edit Number
          </button>
          <div className="mb-8">
            <h2 className="text-2xl font-bold text-slate-900">Verify Identity</h2>
            <p className="text-slate-500 text-sm mt-2">We've sent a 4-digit code to <span className="text-slate-900 font-bold">+{mobileNumber}</span></p>
          </div>
          <form onSubmit={handleVerifyOtp} className="space-y-8">
            <div className="flex justify-between gap-3">
              {otp.map((digit, i) => (
                <input
                  key={i}
                  id={`otp-${i}`}
                  required
                  type="number"
                  className="w-full h-16 text-center text-2xl font-bold bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
                  value={digit}
                  onChange={e => handleOtpChange(i, e.target.value)}
                  onKeyDown={e => {
                    if (e.key === 'Backspace' && !otp[i] && i > 0) {
                      document.getElementById(`otp-${i - 1}`)?.focus();
                    }
                  }}
                />
              ))}
            </div>
            <div className="space-y-4">
              <button 
                type="submit"
                disabled={!otp.every(d => d !== '')}
                className="w-full py-4 bg-emerald-600 text-white font-bold rounded-2xl shadow-xl shadow-emerald-100 disabled:opacity-50 disabled:shadow-none hover:bg-emerald-700 transition-all"
              >
                Verify & Continue
              </button>
              <button type="button" className="w-full py-2 text-indigo-600 font-bold text-sm">Resend Code in 0:30</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-indigo-600 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-500">
        <div className="p-10">
          <div className="flex justify-between items-center mb-10">
            <h2 className="text-2xl font-bold text-slate-900">Setup WealthFlow</h2>
            <div className="flex gap-1.5">
              {[1, 2, 3, 4, 5].map(s => (
                <div key={s} className={`h-1.5 w-8 rounded-full transition-all duration-300 ${step >= s ? 'bg-indigo-600' : 'bg-slate-100'}`}></div>
              ))}
            </div>
          </div>

          {step === 1 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h3 className="text-xl font-bold text-slate-800">Basic Profile</h3>
                <p className="text-slate-500 text-sm">Let's start with who and where you are.</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input placeholder="Name" className="col-span-2 p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                <input placeholder="Designation" className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-medium" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
                <input placeholder="Age" type="number" className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-medium" value={formData.age} onChange={e => setFormData({...formData, age: e.target.value})} />
                <input placeholder="Current City" className="col-span-2 p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-medium" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
                <div className="col-span-2 grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase ml-2 tracking-widest">Country</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none font-medium" value={formData.country} onChange={handleCountryChange}>
                      {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase ml-2 tracking-widest">Currency</label>
                    <input disabled className="w-full p-4 bg-slate-100 border border-slate-100 rounded-2xl outline-none text-slate-500 cursor-not-allowed font-bold" value={formData.currency} />
                  </div>
                </div>
              </div>
              <button onClick={nextStep} disabled={!formData.name} className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Next Step</button>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h3 className="text-xl font-bold text-slate-800">Primary Bank Account</h3>
                <p className="text-slate-500 text-sm">Create your main bank account for initial liquidity.</p>
              </div>
              <div className="space-y-4">
                <input placeholder="Bank Name" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-medium" value={formData.bankName} onChange={e => setFormData({...formData, bankName: e.target.value})} />
                <input placeholder="Account Number (Optional)" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-medium" value={formData.bankAccNum} onChange={e => setFormData({...formData, bankAccNum: e.target.value})} />
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase ml-2 tracking-widest">Opening Balance ({formData.currency})</label>
                  <input placeholder="0.00" type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-800" value={formData.bankBalance} onChange={e => setFormData({...formData, bankBalance: e.target.value})} />
                </div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setStep(step - 1)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl">Back</button>
                <button onClick={() => {
                  if(formData.bankName) addBank({ id: 'init-bank', name: formData.bankName, accountNumber: formData.bankAccNum, balance: Number(formData.bankBalance) });
                  nextStep();
                }} className="flex-[2] py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg shadow-indigo-100">Continue</button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h3 className="text-xl font-bold text-slate-800">Credit Card</h3>
                <p className="text-slate-500 text-sm">Add your primary credit card (Optional).</p>
              </div>
              <div className="space-y-4">
                <input placeholder="Lender Name (e.g. Chase, HDFC)" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-medium" value={formData.cardLender} onChange={e => setFormData({...formData, cardLender: e.target.value})} />
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase ml-2 tracking-widest">Outstanding ({formData.currency})</label>
                    <input placeholder="0.00" type="number" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-rose-600" value={formData.cardBalance} onChange={e => setFormData({...formData, cardBalance: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase ml-2 tracking-widest">Last 4 Digits</label>
                    <input placeholder="XXXX" maxLength={4} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-mono" value={formData.cardLast4} onChange={e => setFormData({...formData, cardLast4: e.target.value})} />
                  </div>
                </div>
                <div className="space-y-2">
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">Card Benefits</p>
                  <div className="grid grid-cols-2 gap-2">
                    {['movie', 'dining', 'concierge', 'lounge'].map(off => (
                      <label key={off} className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl cursor-pointer hover:bg-slate-100 transition-colors">
