export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number; // Current outstanding
  last4: string;
  limit?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity; // For recurring expenses
}

export interface Asset {
  id: string;
  name: string;
  value: number;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet';
  date: string;
  category?: string;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
}

