export default Onboarding;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number; // Current outstanding
  last4: string;
  limit?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity; // For recurring expenses
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  sharedContact?: {
    name: string;
    mobile: string;
  };
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction } from '../types';

interface FinanceContextType {
  state: FinancialState;
  isAuthenticated: boolean;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addBank: (bank: BankAccount) => void;
  addCard: (card: CreditCard) => void;
  addWallet: (wallet: Wallet) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  resetBoarding: () => void;
}

const STORAGE_KEY = 'wealthflow_state';

const initialState: FinancialState = {
  profile: { name: '', designation: '', age: 0, city: '', country: '', currency: 'USD', isBoarded: false },
  banks: [],
  cards: [],
  wallets: [],
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [state, setState] = useState<FinancialState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.transactions) parsed.transactions = [];
      return parsed;
    }
    return initialState;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateProfile = (profile: UserProfile) => setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...prev.banks, bank]
  }));

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...prev.cards, card]
  }));

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...prev.wallets, wallet]
  }));

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...prev.assets, asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...prev.liabilities, liability] }));

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...prev.transactions] };

      const updateBalance = (amount: number, isAdding: boolean) => {
        const delta = isAdding ? amount : -amount;
        if (transaction.accountType === 'bank') {
          newState.banks = prev.banks.map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + delta } : b);
        } else if (transaction.accountType === 'card') {
          const cardDelta = isAdding ? -amount : amount;
          newState.cards = prev.cards.map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
        } else if (transaction.accountType === 'wallet') {
          newState.wallets = prev.wallets.map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + delta } : w);
        }
      };

      const sharedAmt = transaction.sharedAmount || 0;
      const selfAmt = transaction.amount - sharedAmt;

      switch (transaction.type) {
        case 'Income':
          updateBalance(transaction.amount, true);
          // Only non-shared part goes to P&L
          if (selfAmt > 0) {
            newState.incomes = [...prev.incomes, {
              id: transaction.id,
              name: transaction.description,
              amount: selfAmt,
              periodicity: 'Monthly',
              dateOfReceipt: transaction.date
            }];
          }
          // Shared part goes to Balance Sheet as a Liability (Payable)
          if (transaction.isShared && sharedAmt > 0) {
            newState.liabilities = [...prev.liabilities, {
              id: transaction.id + '_shared',
              name: `Payable: ${transaction.sharedContact?.name} (Ref: ${transaction.description})`,
              amount: sharedAmt,
              type: 'Payable'
            }];
          }
          break;

        case 'Expense':
          updateBalance(transaction.amount, false);
          // Only non-shared part goes to P&L
          if (selfAmt > 0) {
            newState.expenses = [...prev.expenses, {
              id: transaction.id,
              category: transaction.category || 'Others',
              amount: selfAmt,
              date: transaction.date
            }];
          }
          // Shared part goes to Balance Sheet as an Asset (Receivable)
          if (transaction.isShared && sharedAmt > 0) {
            newState.assets = [...prev.assets, {
              id: transaction.id + '_shared',
              name: `Receivable: ${transaction.sharedContact?.name} (Ref: ${transaction.description})`,
              value: sharedAmt,
              type: 'Receivable'
            }];
          }
          break;

        case 'Asset':
          updateBalance(transaction.amount, false);
          newState.assets = [...prev.assets, {
            id: transaction.id,
            name: transaction.description,
            value: transaction.amount,
            type: 'Physical'
          }];
          break;

        case 'Liability':
          updateBalance(transaction.amount, true);
          newState.liabilities = [...prev.liabilities, {
            id: transaction.id,
            name: transaction.description,
            amount: transaction.amount,
            type: 'Debt'
          }];
          break;
      }

      return newState;
    });
  };

  const resetBoarding = () => {
    setState(initialState);
    setAuthenticated(false);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, isAuthenticated, setAuthenticated, updateProfile, addBank, addCard, addWallet, 
      addIncome, addExpense, addAsset, addLiability,
      addTransaction, resetBoarding 
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType } from '../types';
import { formatCurrency } from '../utils/formatters';

const Transactions: React.FC = () => {
  const { state, addTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    sharedAmount: '',
    sharedContactName: '',
    sharedContactMobile: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setFormData({ ...initialFormState, type });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const sharedAmount = formData.isShared ? Number(formData.sharedAmount) : 0;

    if (formData.isShared && sharedAmount > totalAmount) {
      alert("Shared amount cannot exceed total amount.");
      return;
    }

    addTransaction({
      id: Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: formData.type === 'Expense' ? formData.category : undefined,
      isShared: formData.isShared,
      sharedAmount: sharedAmount,
      sharedContact: formData.isShared ? {
        name: formData.sharedContactName,
        mobile: formData.sharedContactMobile
      } : undefined
    });

    setShowModal(false);
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal('Income')}
            className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">💰</span> Income
          </button>
          <button 
            onClick={() => handleOpenModal('Expense')}
            className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">📉</span> Expense
          </button>
          <button 
            onClick={() => handleOpenModal('Asset')}
            className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">🏗️</span> Asset
          </button>
          <button 
            onClick={() => handleOpenModal('Liability')}
            className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"
          >
            <span className="text-lg">🧾</span> Liability
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
