  { name: 'Turkmenistan', currency: 'TMT' }, { name: 'Uganda', currency: 'UGX' }, { name: 'Ukraine', currency: 'UAH' },
  { name: 'United Arab Emirates', currency: 'AED' }, { name: 'United Kingdom', currency: 'GBP' }, { name: 'United States', currency: 'USD' },
  { name: 'Uruguay', currency: 'UYU' }, { name: 'Uzbekistan', currency: 'UZS' }, { name: 'Vanuatu', currency: 'VUV' },
  { name: 'Venezuela', currency: 'VES' }, { name: 'Vietnam', currency: 'VND' }, { name: 'Western Sahara', currency: 'MAD' },
  { name: 'Yemen', currency: 'YER' }, { name: 'Zambia', currency: 'ZMW' }, { name: 'Zimbabwe', currency: 'ZWL' }
];

const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet, addLiability } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PERMISSIONS' | 'PROFILE'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [step, setStep] = useState(1);
  const [permissions, setPermissions] = useState({
    contacts: false,
    gallery: false,
    location: false,
    notifications: false,
    backgroundRefresh: true,
  });

  const [formData, setFormData] = useState({
    name: state.profile.name || '',
    designation: state.profile.designation || '',
    age: state.profile.age ? String(state.profile.age) : '',
    city: state.profile.city || '',
    country: state.profile.country || 'United States',
    currency: state.profile.currency || 'USD',
    openingCash: '0'
  });

  const handleSendOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) {
      setAuthState('MFA');
    }
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) {
      setAuthState('PERMISSIONS');
    }
  };

  const handleRequestPermission = async (key: keyof typeof permissions) => {
    if (key === 'location') {
      try {
        await new Promise((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        setPermissions(prev => ({ ...prev, location: true }));
      } catch (err) {
        console.warn('Location permission denied or error:', err);
      }
    } else if (key === 'notifications') {
      if ('Notification' in window) {
        const result = await Notification.requestPermission();
        setPermissions(prev => ({ ...prev, notifications: result === 'granted' }));
      }
    } else {
      setPermissions(prev => ({ ...prev, [key]: !prev[key] }));
    }
  };

  const handlePermissionsDone = () => {
    if (state.profile.isBoarded) {
      setAuthenticated(true);
    } else {
      setAuthState('PROFILE');
    }
  };

  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);
    if (value && index < 3) {
      document.getElementById(`otp-${index + 1}`)?.focus();
    }
  };

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // 1. Update Profile
    updateProfile({
      name: formData.name,
      designation: formData.designation,
      age: Number(formData.age),
      city: formData.city,
      country: formData.country,
      currency: formData.currency,
      mobileNumber: mobileNumber,
      isBoarded: true
    });

    // 2. Add Default Cash Account
    const cashVal = Number(formData.openingCash);
    if (cashVal >= 0) {
      addWallet({
        id: 'default-cash',
        name: 'Cash',
        balance: cashVal
      });
    } else {
      addLiability({
        id: 'default-cash-overdraft',
        name: 'Cash (Overdraft)',
        amount: Math.abs(cashVal),
        type: 'Debt'
      });
    }

    setAuthenticated(true);
  };

  const updateCountry = (countryName: string) => {
    const country = countries.find(c => c.name === countryName);
    setFormData({
      ...formData,
      country: countryName,
      currency: country ? country.currency : 'USD'
    });
  };

  if (authState === 'MOBILE') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/20 rounded-full -mr-48 -mt-48 blur-3xl"></div>
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-emerald-600/10 rounded-full -ml-32 -mb-32 blur-3xl"></div>
        <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-10 z-10 animate-in fade-in zoom-in duration-300">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-50 rounded-2xl flex items-center justify-center text-4xl mx-auto mb-6 shadow-sm border border-indigo-100">💎</div>
            <h2 className="text-3xl font-bold text-slate-900 tracking-tight">WealthFlow</h2>
            <p className="text-slate-500 mt-2 font-medium">Your global financial command center</p>
          </div>
          <form onSubmit={handleSendOtp} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Mobile Access</label>
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold transition-colors group-focus-within:text-indigo-600">+</span>
                <input 
                  required
                  type="tel"
                  placeholder="Enter registered mobile number"
                  className="w-full p-4 pl-8 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold transition-all text-slate-800 placeholder:font-normal placeholder:text-slate-300"
                  value={mobileNumber}
                  onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))}
                />
              </div>
            </div>
            <button 
              type="submit"
              disabled={mobileNumber.length < 8}
              className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all disabled:opacity-50 active:scale-95"
            >
              Secure Login
            </button>
          </form>
          <div className="mt-10 flex items-center gap-3 justify-center opacity-40">
             <div className="h-px bg-slate-300 flex-1"></div>
             <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Enterprise Security</span>
             <div className="h-px bg-slate-300 flex-1"></div>
          </div>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-10 animate-in fade-in slide-in-from-right-8 duration-300">
          <button onClick={() => setAuthState('MOBILE')} className="text-slate-400 hover:text-indigo-600 text-sm font-bold flex items-center gap-2 mb-8 transition-colors">
            ← Change Identification
          </button>
          <div className="mb-10">
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-amber-50 border border-amber-100 rounded-full text-[10px] font-bold text-amber-600 uppercase mb-4 tracking-wider">
               <span className="animate-pulse">●</span> Multi-Factor Authentication
            </div>
            <h2 className="text-3xl font-bold text-slate-900">Verify Identity</h2>
            <p className="text-slate-500 mt-2 font-medium">Verify the 4-digit token sent to <span className="text-slate-900 font-bold">+{mobileNumber}</span></p>
          </div>
          <form onSubmit={handleVerifyMfa} className="space-y-8">
            <div className="flex justify-between gap-3">
              {otp.map((digit, i) => (
                <input
                  key={i}
                  id={`otp-${i}`}
                  required
                  type="number"
                  className="w-full h-16 text-center text-3xl font-bold bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all shadow-sm"
                  value={digit}
                  onChange={e => handleOtpChange(i, e.target.value)}
                  onKeyDown={e => {
                    if (e.key === 'Backspace' && !otp[i] && i > 0) {
                      document.getElementById(`otp-${i - 1}`)?.focus();
                    }
                  }}
                />
              ))}
            </div>
            <button 
              type="submit"
              disabled={!otp.every(d => d !== '')}
              className="w-full py-4 bg-emerald-600 text-white font-bold rounded-2xl shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all disabled:opacity-50 active:scale-95"
            >
              Complete Verification
            </button>
            <p className="text-center text-xs font-medium text-slate-400">
              Didn't receive it? <button type="button" className="text-indigo-600 font-bold hover:underline">Resend OTP</button>
            </p>
          </form>
        </div>
      </div>
    );
  }

  if (authState === 'PERMISSIONS') {
    const permissionList = [
      { id: 'location', label: 'Precise Location', desc: 'Auto-detect currency and local banking standards.', icon: '📍', browser: true },
      { id: 'notifications', label: 'Push Notifications', desc: 'Instant alerts for unusual spending and budget milestones.', icon: '🔔', browser: true },
      { id: 'contacts', label: 'Sync Contacts', desc: 'Easily send payments and split bills with friends.', icon: '👥', browser: false },
      { id: 'gallery', label: 'Gallery Access', desc: 'Scan receipts and upload profile documents directly.', icon: '🖼️', browser: false },
      { id: 'backgroundRefresh', label: 'Background Sync', desc: 'Keep your balance sheets updated even when offline.', icon: '🔄', browser: false },
    ];

    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-10 animate-in fade-in slide-in-from-bottom-8 duration-300">
          <div className="mb-8">
            <h2 className="text-2xl font-bold text-slate-900">System Access</h2>
            <p className="text-slate-500 text-sm mt-1">Enable sync to unlock the full potential of WealthFlow.</p>
          </div>
          <div className="space-y-4 mb-10">
            {permissionList.map((perm) => (
              <div 
                key={perm.id} 
                onClick={() => handleRequestPermission(perm.id as keyof typeof permissions)}
                className={`p-4 rounded-2xl border transition-all cursor-pointer flex items-center gap-4 ${
                  permissions[perm.id as keyof typeof permissions] 
                    ? 'bg-indigo-50 border-indigo-200' 
                    : 'bg-slate-50 border-slate-100 hover:border-slate-200'
                }`}
              >
                <div className="w-10 h-10 rounded-xl bg-white shadow-sm flex items-center justify-center text-xl">{perm.icon}</div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-800">{perm.label}</p>
                  <p className="text-[10px] text-slate-400 leading-tight font-medium">{perm.desc}</p>
                </div>
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                  permissions[perm.id as keyof typeof permissions]
                    ? 'bg-indigo-600 border-indigo-600'
                    : 'bg-white border-slate-200'
                }`}>
                  {permissions[perm.id as keyof typeof permissions] && (
                    <span className="text-white text-[10px] font-bold">✓</span>
                  )}
                </div>
              </div>
            ))}
          </div>
          <button 
            onClick={handlePermissionsDone}
            className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95"
          >
            Allow Selected & Continue
          </button>
          <p className="text-center text-[10px] text-slate-400 mt-6 uppercase tracking-widest font-bold">Permissions can be revoked in profile</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="w-full max-w-xl bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-500">
        <div className="bg-indigo-600 p-10 text-white relative">
          <div className="relative z-10">
            <h2 className="text-3xl font-bold mb-2">Initialize Profile 🚀</h2>
            <p className="text-indigo-100 opacity-80">Tell us where you are to localize your experience.</p>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-20 text-8xl font-black italic">WF</div>
        </div>
        <form onSubmit={handleSubmit} className="p-10">
          {step === 1 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Full Identity</label>
                <input
                  required
                  placeholder="e.g. Alexander Hamilton"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Professional Title</label>
                <input
                  required
                  placeholder="e.g. Managing Director / Chief Engineer"
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all"
                  value={formData.designation}
                  onChange={e => setFormData({...formData, designation: e.target.value})}
                />
              </div>
              <button 
                type="button"
                onClick={handleNext}
                disabled={!formData.name || !formData.designation}
                className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all disabled:opacity-50 active:scale-95"
              >
                Continue Setup
              </button>
            </div>
          )}
          {step === 2 && (
            <div className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Age</label>
                  <input
                    required
                    type="number"
                    placeholder="30"
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"
                    value={formData.age}
                    onChange={e => setFormData({...formData, age: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Current City</label>
                  <input
                    required
                    placeholder="e.g. Singapore / New York"
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium"
                    value={formData.city}
                    onChange={e => setFormData({...formData, city: e.target.value})}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Global Location</label>
                <div className="relative">
                  <select
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold appearance-none cursor-pointer"
                    value={formData.country}
                    onChange={e => updateCountry(e.target.value)}
                  >
                    {countries.sort((a,b) => a.name.localeCompare(b.name)).map(c => (
                      <option key={c.name} value={c.name}>{c.name}</option>
                    ))}
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">▼</div>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Opening Cash Balance ({formData.currency})</label>
                  <input
                    required
                    type="number"
                    placeholder="0.00"
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"
                    value={formData.openingCash}
                    onChange={e => setFormData({...formData, openingCash: e.target.value})}
                  />
                  <p className="text-[10px] text-slate-400 italic">Positive for Asset, Negative for Liability (Overdraft).</p>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Reporting Currency</label>
                <div className="w-full p-4 bg-emerald-50 border border-emerald-100 rounded-2xl text-emerald-700 font-black text-xl flex items-center justify-between shadow-sm">
                  <span>{formData.currency}</span>
                  <div className="flex flex-col items-end">
                    <span className="text-[8px] text-emerald-400 uppercase font-black tracking-widest">Auto-Assigned</span>
                  </div>
                </div>
              </div>

              <div className="flex gap-4">
                <button 
                  type="button"
                  onClick={handleBack}
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all active:scale-95"
                >
                  Back
                </button>
                <button 
                  type="submit"
                  disabled={!formData.age || !formData.city}
                  className="flex-[2] py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all disabled:opacity-50 active:scale-95"
                >
                  Create Dashboard
                </button>
              </div>
            </div>
          )}
        </form>
        <div className="px-10 pb-10 flex justify-center gap-3">
          <div className={`h-1.5 rounded-full transition-all duration-300 ${step === 1 ? 'w-10 bg-indigo-600' : 'w-4 bg-slate-200'}`}></div>
          <div className={`h-1.5 rounded-full transition-all duration-300 ${step === 2 ? 'w-10 bg-indigo-600' : 'w-4 bg-slate-200'}`}></div>
        </div>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numOthers: '1',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Initialize contacts array when numOthers changes
  useEffect(() => {
    if (!formData.isShared) return;
    const n = Math.max(1, Number(formData.numOthers) || 1);
    const currentContacts = [...formData.contacts];

    if (currentContacts.length < n) {
      for (let i = currentContacts.length; i < n; i++) {
        currentContacts.push({ name: '', mobile: '' });
      }
    } else if (currentContacts.length > n) {
      currentContacts.splice(n);
    }

    setFormData(prev => ({ ...prev, contacts: currentContacts }));
  }, [formData.numOthers, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [{ name: '', mobile: '' }] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 1;
    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numOthers: String(nOthers),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [{ name: '', mobile: '' }]
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const total = Number(formData.amount) || 0;
    const nOthers = Math.max(1, Number(formData.numOthers) || 1);
    const totalParticipants = nOthers + (formData.includeSelf ? 1 : 0);

    if (total <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return formData.includeSelf 
          ? total - (total / totalParticipants)
          : total;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * total;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        return (cS / (uS + cS)) * total;
      case 'adjustment':
        const baseSharePerPerson = total / totalParticipants;
        return (nOthers * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared && (finalSharedAmount > totalAmount || finalSharedAmount < 0)) {
      alert("Invalid shared amount. Please check your split calculation.");
      return;
    }

    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: finalSharedAmount / (formData.contacts.length || 1)
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? (Number(formData.numOthers) + (formData.includeSelf ? 1 : 0)) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    if (editingId) {
      updateTransaction(transactionData);
    } else {
      addTransaction(transactionData);
    }

    setShowModal(false);
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 my-8">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Number of Other People</label>
                          <input required type="number" min="1" className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.numOthers} onChange={e => setFormData({ ...formData, numOthers: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        {formData.contacts.map((contact, idx) => (
                          <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group">
                            <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                              <div className="space-y-1">
                                <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                              </div>
                            </div>
                            <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(totalOtherShare / (formData.contacts.length || 1), currency)}</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-1 px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numOthers: '1',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Initialize contacts array when numOthers changes
  useEffect(() => {
    if (!formData.isShared) return;
    const n = Math.max(1, Number(formData.numOthers) || 1);
    const currentContacts = [...formData.contacts];

    if (currentContacts.length < n) {
      for (let i = currentContacts.length; i < n; i++) {
        currentContacts.push({ name: '', mobile: '' });
      }
    } else if (currentContacts.length > n) {
      currentContacts.splice(n);
    }

    setFormData(prev => ({ ...prev, contacts: currentContacts }));
  }, [formData.numOthers, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [{ name: '', mobile: '' }] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 1;
    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numOthers: String(nOthers),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [{ name: '', mobile: '' }]
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const total = Number(formData.amount) || 0;
    const nOthers = Math.max(1, Number(formData.numOthers) || 1);
    const totalParticipants = nOthers + (formData.includeSelf ? 1 : 0);

    if (total <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return formData.includeSelf 
          ? total - (total / totalParticipants)
          : total;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * total;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        return (cS / (uS + cS)) * total;
      case 'adjustment':
        const baseSharePerPerson = total / totalParticipants;
        return (nOthers * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared && (finalSharedAmount > totalAmount || finalSharedAmount < 0)) {
      alert("Invalid shared amount. Please check your split calculation.");
      return;
    }

    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: finalSharedAmount / (formData.contacts.length || 1)
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? (Number(formData.numOthers) + (formData.includeSelf ? 1 : 0)) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    if (editingId) {
      updateTransaction(transactionData);
    } else {
      addTransaction(transactionData);
    }

    setShowModal(false);
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Number of Other People</label>
                          <input required type="number" min="1" className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.numOthers} onChange={e => setFormData({ ...formData, numOthers: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(totalOtherShare / (formData.contacts.length || 1), currency)}</div>
                            </div>
