              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Initialize contacts array when totalParticipants or includeSelf changes
  useEffect(() => {
    if (!formData.isShared) return;

    const total = Math.max(1, Number(formData.totalParticipants) || 1);
    const requiredOthers = formData.includeSelf ? total - 1 : total;

    // Ensure we don't have negative contacts
    const finalCount = Math.max(0, requiredOthers);

    const currentContacts = [...formData.contacts];

    if (currentContacts.length < finalCount) {
      for (let i = currentContacts.length; i < finalCount; i++) {
        currentContacts.push({ name: '', mobile: '' });
      }
    } else if (currentContacts.length > finalCount) {
      currentContacts.splice(finalCount);
    }

    setFormData(prev => ({ ...prev, contacts: currentContacts }));
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [{ name: '', mobile: '' }] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        // Share per person is totalValue / totalParts
        // Total shared is sharePerPerson * othersCount
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        return (cS / (uS + cS)) * totalValue;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared && (finalSharedAmount > totalAmount || finalSharedAmount < 0)) {
      alert("Invalid shared amount. Please check your split calculation.");
      return;
    }

    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: finalSharedAmount / (formData.contacts.length || 1)
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    if (editingId) {
      updateTransaction(transactionData);
    } else {
      addTransaction(transactionData);
    }

    setShowModal(false);
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(totalOtherShare / (formData.contacts.length || 1), currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants to assign. You are the sole participant.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Initialize contacts array when totalParticipants or includeSelf changes
  useEffect(() => {
    if (!formData.isShared) return;

    const total = Math.max(1, Number(formData.totalParticipants) || 1);
    const requiredOthers = formData.includeSelf ? total - 1 : total;

    // Ensure we don't have negative contacts
    const finalCount = Math.max(0, requiredOthers);

    const currentContacts = [...formData.contacts];

    if (currentContacts.length < finalCount) {
      for (let i = currentContacts.length; i < finalCount; i++) {
        currentContacts.push({ name: '', mobile: '' });
      }
    } else if (currentContacts.length > finalCount) {
      currentContacts.splice(finalCount);
    }

    setFormData(prev => ({ ...prev, contacts: currentContacts }));
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [{ name: '', mobile: '' }] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        // Share per person is totalValue / totalParts
        // Total shared is sharePerPerson * othersCount
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        return (cS / (uS + cS)) * totalValue;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared && (finalSharedAmount > totalAmount || finalSharedAmount < 0)) {
      alert("Invalid shared amount. Please check your split calculation.");
      return;
    }

    // Duplicate Mobile Number Check
    if (formData.isShared) {
      const allMobiles = formData.contacts.map(c => c.mobile.trim()).filter(m => m !== '');
      if (formData.includeSelf && state.profile.mobileNumber) {
        allMobiles.push(state.profile.mobileNumber.trim());
      }

      const uniqueMobiles = new Set(allMobiles);
      if (uniqueMobiles.size !== allMobiles.length) {
        const confirmDup = window.confirm(
          "Warning: Multiple participants have the same mobile number. " +
          "This might lead to confusion in ledgers. Do you want to proceed anyway?"
        );
        if (!confirmDup) return;
      }
    }

    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: finalSharedAmount / (formData.contacts.length || 1)
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    if (editingId) {
      updateTransaction(transactionData);
    } else {
      addTransaction(transactionData);
    }

    setShowModal(false);
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(totalOtherShare / (formData.contacts.length || 1), currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants to assign. You are the sole participant.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Initialize contacts array when totalParticipants or includeSelf changes
  useEffect(() => {
    if (!formData.isShared) return;

    const total = Math.max(1, Number(formData.totalParticipants) || 1);
    const requiredOthers = formData.includeSelf ? total - 1 : total;

    // Ensure we don't have negative contacts
    const finalCount = Math.max(0, requiredOthers);

    const currentContacts = [...formData.contacts];

    if (currentContacts.length < finalCount) {
      for (let i = currentContacts.length; i < finalCount; i++) {
        currentContacts.push({ name: '', mobile: '' });
      }
    } else if (currentContacts.length > finalCount) {
      currentContacts.splice(finalCount);
    }

    setFormData(prev => ({ ...prev, contacts: currentContacts }));
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [{ name: '', mobile: '' }] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        // Share per person is totalValue / totalParts
        // Total shared is sharePerPerson * othersCount
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        return (cS / (uS + cS)) * totalValue;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    // 1. Basic Value Validation
    if (formData.isShared && (finalSharedAmount > totalAmount || finalSharedAmount < 0)) {
      alert("Invalid shared amount. Please check your split calculation.");
      return;
    }

    // 2. Duplicate Mobile Number Validation
    if (formData.isShared) {
      // Normalize function: remove non-digits to compare numbers like "123 456" and "123-456"
      const normalize = (num: string) => num.replace(/\D/g, '');

      const allMobilesNormalized: string[] = formData.contacts
        .map(c => normalize(c.mobile))
        .filter(m => m !== '');

      if (formData.includeSelf && state.profile.mobileNumber) {
        allMobilesNormalized.push(normalize(state.profile.mobileNumber));
      }

      const uniqueMobiles = new Set(allMobilesNormalized);
      if (uniqueMobiles.size !== allMobilesNormalized.length) {
        const confirmDuplicate = window.confirm(
          "Multiple participants (possibly including you) have the same mobile number. " +
          "This might lead to overlapping ledger entries. Do you wish to proceed?"
        );
        if (!confirmDuplicate) {
          return; // Stop submission if user clicks Cancel
        }
      }
    }

    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: finalSharedAmount / (formData.contacts.length || 1)
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    if (editingId) {
      updateTransaction(transactionData);
    } else {
      addTransaction(transactionData);
    }

    setShowModal(false);
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(totalOtherShare / (formData.contacts.length || 1), currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants to assign. You are the sole participant.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Synchronize contacts list based on participant counts
  useEffect(() => {
    if (!formData.isShared) return;

    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;

    // Final check for non-negative count
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;

      if (currentContacts.length < finalCount) {
        // Add empty contacts
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        // Trim contacts
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) {
      alert("Please select a valid account.");
      return;
    }

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    // 1. Basic Value Validation
    if (formData.isShared) {
      if (finalSharedAmount > totalAmount) {
        alert("The shared portion cannot exceed the total transaction amount.");
        return;
      }
      if (finalSharedAmount < 0) {
        alert("Shared amount cannot be negative.");
        return;
      }
    }

    // 2. Duplicate Mobile Number Validation
    if (formData.isShared) {
      const normalize = (num: string) => num.replace(/\D/g, '');
      const mobilesToCompare: string[] = [];

      // Add participant mobiles
      formData.contacts.forEach(c => {
        const m = normalize(c.mobile);
        if (m) mobilesToCompare.push(m);
      });

      // Add user's mobile if they are participating
      if (formData.includeSelf && state.profile.mobileNumber) {
        const userM = normalize(state.profile.mobileNumber);
        if (userM) mobilesToCompare.push(userM);
      }

      // Check for any duplicates in the aggregated list
      const duplicates = mobilesToCompare.filter((item, index) => mobilesToCompare.indexOf(item) !== index);
      if (duplicates.length > 0) {
        const uniqueDups = [...new Set(duplicates)];
        const confirmMsg = `Duplicate mobile number(s) detected: ${uniqueDups.join(', ')}. This is usually not recommended for distinct participants. Do you wish to proceed anyway?`;
        if (!window.confirm(confirmMsg)) {
          return; // Stop submission
        }
      }
    }

    // 3. Prepare shared contacts data
    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: formData.contacts.length > 0 ? finalSharedAmount / formData.contacts.length : 0
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    try {
      if (editingId) {
        updateTransaction(transactionData);
      } else {
        addTransaction(transactionData);
      }
      setShowModal(false);
    } catch (err) {
      console.error("Error saving transaction:", err);
      alert("An unexpected error occurred while saving. Please check the console.");
    }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" step="any" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" step="any" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" step="any" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" step="any" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(formData.contacts.length > 0 ? totalOtherShare / formData.contacts.length : 0, currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants to assign. You are participating alone in this split.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Synchronize contacts list based on participant counts
  useEffect(() => {
    if (!formData.isShared) return;

    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;

    // Final check for non-negative count
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;

      if (currentContacts.length < finalCount) {
        // Add empty contacts
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        // Trim contacts
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  // Derived state: check for duplicates live for UI feedback
  const duplicateMobiles = useMemo(() => {
    if (!formData.isShared) return [];
    const normalize = (num: string) => num.replace(/\D/g, '');
    const mobiles: string[] = [];

    formData.contacts.forEach(c => {
      const m = normalize(c.mobile);
      if (m) mobiles.push(m);
    });

    if (formData.includeSelf && state.profile.mobileNumber) {
      const userM = normalize(state.profile.mobileNumber);
      if (userM) mobiles.push(userM);
    }

    return mobiles.filter((item, index) => mobiles.indexOf(item) !== index);
  }, [formData.contacts, formData.includeSelf, formData.isShared, state.profile.mobileNumber]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Use early preventDefault and separate logic to ensure no race conditions with window.confirm
    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) {
      alert("Please select a valid funding account.");
      return;
    }

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    // 1. Value Validation
    if (formData.isShared) {
      if (finalSharedAmount > totalAmount) {
        alert("The shared portion exceeds the total amount. Please check your split.");
        return;
      }
    }

    // 2. Explicit Duplicate Check with user confirmation
    if (formData.isShared && duplicateMobiles.length > 0) {
      const uniqueDups = Array.from(new Set(duplicateMobiles));
      const confirmMsg = `Wait! Multiple participants use the same mobile number: ${uniqueDups.join(', ')}. \n\nThis could make it hard to identify individual balances later. Do you want to save this transaction anyway?`;

      const userConfirmed = window.confirm(confirmMsg);
      if (!userConfirmed) return; // User opted to cancel the save
    }

    // 3. Construct transaction object
    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: formData.contacts.length > 0 ? finalSharedAmount / formData.contacts.length : 0
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    try {
      if (editingId) {
        updateTransaction(transactionData);
      } else {
        addTransaction(transactionData);
      }
      setShowModal(false);
    } catch (err) {
      console.error("Failed to save transaction:", err);
      alert("Error saving transaction. Check console for details.");
    }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" step="any" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" step="any" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" step="any" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" step="any" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      {duplicateMobiles.length > 0 && (
                        <div className="p-3 bg-amber-50 border border-amber-200 rounded-xl flex items-center gap-3 animate-pulse">
                          <span className="text-xl">⚠️</span>
                          <p className="text-[10px] font-bold text-amber-700 leading-tight">
                            Duplicate mobile numbers detected. You will be asked to confirm this when saving.
                          </p>
                        </div>
                      )}

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(formData.contacts.length > 0 ? totalOtherShare / formData.contacts.length : 0, currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants to assign. You are participating alone in this split.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Synchronize contacts list based on participant counts
  useEffect(() => {
    if (!formData.isShared) return;

    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;

    // Final check for non-negative count
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;

      if (currentContacts.length < finalCount) {
        // Add empty contacts
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        // Trim contacts
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  // UI Helper for displaying live warnings (doesn't block submit)
  const hasLiveDuplicates = useMemo(() => {
    if (!formData.isShared) return false;
    const normalize = (num: string) => num.replace(/\D/g, '');
    const mobiles: string[] = formData.contacts
      .map(c => normalize(c.mobile))
      .filter(m => m !== '');

    if (formData.includeSelf && state.profile.mobileNumber) {
      const userM = normalize(state.profile.mobileNumber);
      if (userM) mobiles.push(userM);
    }

    const unique = new Set(mobiles);
    return unique.size !== mobiles.length;
  }, [formData.contacts, formData.includeSelf, formData.isShared, state.profile.mobileNumber]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) {
      alert("Please select a funding source.");
      return;
    }

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared) {
      if (finalSharedAmount > totalAmount) {
        alert("The shared portion cannot be greater than the total amount.");
        return;
      }

      // VITAL: Duplicate Mobile Number Check within the submit handler
      const normalize = (num: string) => num.replace(/\D/g, '');
      const mobilesInCurrentForm: string[] = formData.contacts
        .map(c => normalize(c.mobile))
        .filter(m => m !== '');

      if (formData.includeSelf && state.profile.mobileNumber) {
        const userM = normalize(state.profile.mobileNumber);
        if (userM) mobilesInCurrentForm.push(userM);
      }

      const duplicateList = mobilesInCurrentForm.filter((item, index) => mobilesInCurrentForm.indexOf(item) !== index);

      if (duplicateList.length > 0) {
        const uniqueDups = Array.from(new Set(duplicateList));
        // This is the core requirement: asking for confirmation
        const userAgreed = window.confirm(
          `Alert: Identical mobile numbers detected for multiple participants (${uniqueDups.join(', ')}). \n\nDo you want to proceed and save this transaction with these duplicates?`
        );

        if (!userAgreed) {
          return; // If they click 'Cancel', we exit and don't save
        }
      }
    }

    // Process saving
    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: formData.contacts.length > 0 ? finalSharedAmount / formData.contacts.length : 0
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    try {
      if (editingId) {
        updateTransaction(transactionData);
      } else {
        addTransaction(transactionData);
      }
      setShowModal(false);
    } catch (err) {
      console.error("Save failed:", err);
      alert("An error occurred while saving. Please try again.");
    }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-colors" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {state.transactions.length === 0 && (
                <tr><td colSpan={6} className="px-6 py-16 text-center"><div className="flex flex-col items-center gap-2 opacity-40"><span className="text-4xl">📂</span><p className="text-slate-500 font-medium italic">No ledger entries recorded yet.</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Record'} {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Account</label>
                <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                  <option value="">Choose Funding Source</option>
                  {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Amount ({currency})</label>
                  <input required type="number" placeholder="0.00" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100 space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">🤝</span>
                      <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest">Shared Transaction?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-2 animate-in fade-in slide-in-from-top-2 duration-300">

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Include yourself in split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl">
                            <input 
                              type="checkbox" 
                              className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500"
                              checked={formData.includeSelf} 
                              onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} 
                            />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Yes, I am a participant' : 'No, others only'}</span>
                          </div>
                        </div>

                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Participants</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Division Method</label>
                        <div className="flex overflow-x-auto gap-2 pb-2 no-scrollbar">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id, splitValue: opt.id === 'equal' ? '' : formData.splitValue })}
                              className={`flex-shrink-0 px-4 py-2 rounded-xl text-xs font-bold border transition-all flex items-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'
                              }`}
                            >
                              <span>{opt.icon}</span> {opt.label}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="bg-white p-4 rounded-xl border border-indigo-100 shadow-sm space-y-4">
                        {formData.splitType === 'exact' && (
                          <input required type="number" step="any" placeholder="Total shared amount for others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.sharedAmount} onChange={e => setFormData({ ...formData, sharedAmount: e.target.value })} />
                        )}
                        {formData.splitType === 'percentage' && (
                          <input required type="number" max="100" placeholder="Percent to share with others" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}
                        {formData.splitType === 'shares' && (
                          <div className="grid grid-cols-2 gap-3">
                            <input disabled={!formData.includeSelf} required={formData.includeSelf} type="number" step="any" placeholder="User Shares" className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-lg ${!formData.includeSelf ? 'opacity-50 grayscale cursor-not-allowed' : ''}`} value={formData.includeSelf ? formData.userShares : '0'} onChange={e => setFormData({ ...formData, userShares: e.target.value })} />
                            <input required type="number" step="any" placeholder="Others Total Shares" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.contactShares} onChange={e => setFormData({ ...formData, contactShares: e.target.value })} />
                          </div>
                        )}
                        {formData.splitType === 'adjustment' && (
                          <input required type="number" step="any" placeholder="Adjustment (+/-) on fair split" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg" value={formData.splitValue} onChange={e => setFormData({ ...formData, splitValue: e.target.value })} />
                        )}

                        <div className="pt-2 flex items-center justify-between border-t border-slate-50 text-center">
                           <div>
                              <p className="text-[8px] font-bold text-slate-400 uppercase">My Portion</p>
                              <p className="text-sm font-bold text-slate-700">{formatCurrency(Number(formData.amount) - totalOtherShare, currency)}</p>
                           </div>
                           <div className="h-6 w-px bg-slate-100"></div>
                           <div>
                              <p className="text-[8px] font-bold text-indigo-400 uppercase">Total Shared Portion</p>
                              <p className="text-sm font-bold text-indigo-600">{formatCurrency(totalOtherShare, currency)}</p>
                           </div>
                        </div>
                      </div>

                      {hasLiveDuplicates && (
                        <div className="p-3 bg-amber-50 border border-amber-200 rounded-xl flex items-center gap-3 animate-pulse">
                          <span className="text-xl">⚠️</span>
                          <p className="text-[10px] font-bold text-amber-700 leading-tight">
                            Same mobile numbers detected. You must confirm this when saving.
                          </p>
                        </div>
                      )}

                      <div className="space-y-4">
                        <label className="text-[10px] font-bold text-indigo-700 uppercase tracking-widest block">Assign Other Participants ({formData.type === 'Income' ? 'Payees' : 'Debtors'})</label>
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-4 custom-scrollbar">
                          {formData.contacts.map((contact, idx) => (
                            <div key={idx} className="p-4 bg-white border border-slate-200 rounded-2xl space-y-3 relative group shadow-sm">
                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(formData.contacts.length > 0 ? totalOtherShare / formData.contacts.length : 0, currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants required for this split.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[]
  };

  const [formData, setFormData] = useState(initialFormState);

  // Synchronize contacts list based on participant counts
  useEffect(() => {
    if (!formData.isShared) return;

    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;

    // Final check for non-negative count
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;

      if (currentContacts.length < finalCount) {
        // Add empty contacts
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        // Trim contacts
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  // UI Helper for displaying live warnings (doesn't block submit)
  const hasLiveDuplicates = useMemo(() => {
    if (!formData.isShared) return false;
    const normalize = (num: string) => num.replace(/\D/g, '');
    const mobiles: string[] = formData.contacts
      .map(c => normalize(c.mobile))
      .filter(m => m !== '');

    if (formData.includeSelf && state.profile.mobileNumber) {
      const userM = normalize(state.profile.mobileNumber);
      if (userM) mobiles.push(userM);
    }

    const unique = new Set(mobiles);
    return unique.size !== mobiles.length;
  }, [formData.contacts, formData.includeSelf, formData.isShared, state.profile.mobileNumber]);

  const accounts = [
    ...state.banks.map(b => ({ id: b.id, name: b.name, type: 'bank' as const })),
    ...state.cards.map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const })),
    ...state.wallets.map(w => ({ id: w.id, name: w.name, type: 'wallet' as const })),
    ...state.liabilities.filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const }))
  ];

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || []
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Are you sure you want to delete this transaction? This will reverse all associated balance changes.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;

    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal':
        return (totalValue / totalParts) * othersCount;
      case 'exact':
        return Number(formData.sharedAmount) || 0;
      case 'percentage':
        return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default:
        return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const account = accounts.find(a => a.id === formData.accountId);
    if (!account) {
      alert("Please select a funding source.");
      return;
    }

    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    if (formData.isShared) {
      if (finalSharedAmount > totalAmount) {
        alert("The shared portion cannot be greater than the total amount.");
        return;
      }
      // Note: blocking duplicate confirmation check removed per user request
    }

    // Process saving
    const sharedContacts: SharedContact[] = formData.contacts.map(c => ({
      name: c.name,
      mobile: c.mobile,
      amount: formData.contacts.length > 0 ? finalSharedAmount / formData.contacts.length : 0
    }));

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined
    };

    try {
      if (editingId) {
        updateTransaction(transactionData);
      } else {
        addTransaction(transactionData);
      }
      setShowModal(false);
    } catch (err) {
      console.error("Save failed:", err);
      alert("An error occurred while saving. Please try again.");
    }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percentage', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjustment', icon: '➕' },
  ];

  return (
    <div className="space-y-8">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Records</h3>
          <p className="text-sm text-slate-500">Track and manage your cash flows.</p>
        </div>

        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="flex-1 sm:flex-none px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100 flex items-center justify-center gap-2"><span className="text-lg">💰</span> Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="flex-1 sm:flex-none px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg shadow-rose-100 flex items-center justify-center gap-2"><span className="text-lg">📉</span> Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="flex-1 sm:flex-none px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 flex items-center justify-center gap-2"><span className="text-lg">🏗️</span> Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="flex-1 sm:flex-none px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg shadow-amber-100 flex items-center justify-center gap-2"><span className="text-lg">🧾</span> Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Type</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.transactions.map(t => {
                const account = accounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4"><p className="text-sm font-semibold text-slate-600">{t.date}</p></td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-0.5">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold tracking-tight">{t.category}</span>}
                        {t.isShared && t.sharedContacts && (
                          <span className="text-[10px] text-indigo-400 italic">
                            Shared with: {t.sharedContacts.map(c => c.name).join(', ')} 
                            ({formatCurrency(t.sharedAmount || 0, currency)})
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase ${
                        t.type === 'Income' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                        t.type === 'Expense' ? 'bg-rose-50 text-rose-600 border border-rose-100' :
                        t.type === 'Asset' ? 'bg-blue-50 text-blue-600 border border-blue-100' :
                        'bg-amber-50 text-amber-600 border border-amber-100'
                      }`}>{t.type}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1.5 py-0.5 rounded capitalize">{account?.type}</span>
                         <span className="text-sm font-medium text-slate-600">{account?.name || 'Unknown'}</span>
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors" title="Edit Entry">✏️</button>
