                  <input required type="number" placeholder="0.00" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-bold text-slate-800" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
