                              <span className="absolute -left-2 -top-2 w-6 h-6 bg-indigo-600 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-md">{idx + 1}</span>
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Name</label>
                                  <input required placeholder="Participant Name" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.name} onChange={e => updateContact(idx, 'name', e.target.value)} />
                                </div>
                                <div className="space-y-1">
                                  <label className="text-[8px] font-bold text-slate-400 uppercase">Mobile</label>
                                  <input required placeholder="Contact Number" className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:ring-1 focus:ring-indigo-500" value={contact.mobile} onChange={e => updateContact(idx, 'mobile', e.target.value)} />
                                </div>
                              </div>
                              <div className="text-[9px] text-slate-400 italic text-right font-medium">Individual Share: {formatCurrency(formData.contacts.length > 0 ? totalOtherShare / formData.contacts.length : 0, currency)}</div>
                            </div>
                          ))}
                          {formData.contacts.length === 0 && formData.includeSelf && (
                            <div className="p-8 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                              <p className="text-xs text-slate-400 italic">No other participants required for this split.</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {formData.type === 'Expense' && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Expense Category</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option>Grocery</option><option>Rent</option><option>Electricity</option><option>Commute</option><option>Dining Out</option><option>Entertainment</option><option>Health</option><option>Others</option>
                  </select>
                </div>
              )}

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Memo / Description</label>
                <input required placeholder="What was this for?" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors">Discard</button>
                <button type="submit" className={`flex-[2] px-4 py-4 text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 ${
                    formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-100' :
                    formData.type === 'Expense' ? 'bg-rose-600 shadow-rose-100' :
                    formData.type === 'Asset' ? 'bg-blue-600 shadow-blue-100' :
                    'bg-amber-600 shadow-amber-100'
                  }`}>{editingId ? 'Update' : 'Save'} Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default Transactions;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string; // undefined means the main user
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; // Who initiated/owns this transaction
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
}

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember } from '../types';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[]; // empty means just "Me", ['all'] means "Family", others specific
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => void;
  removeFamilyMember: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  addCard: (card: CreditCard) => void;
  addWallet: (wallet: Wallet) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  resetBoarding: () => void;
}

const STORAGE_KEY = 'wealthflow_state';

const initialState: FinancialState = {
  profile: { name: '', designation: '', age: 0, city: '', country: '', currency: 'USD', isBoarded: false, familyMembers: [] },
  banks: [],
  cards: [],
  wallets: [],
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]); // Default: Me
  const [state, setState] = useState<FinancialState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.transactions) parsed.transactions = [];
      if (!parsed.profile.familyMembers) parsed.profile.familyMembers = [];
      return parsed;
    }
    return initialState;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const updateProfile = (profile: UserProfile) => setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));

  const addFamilyMember = (member: FamilyMember) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: [...prev.profile.familyMembers, member] }
  }));

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: prev.profile.familyMembers.filter(m => m.id !== id) }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ ...prev, banks: [...prev.banks, bank] }));
  const addCard = (card: CreditCard) => setState(prev => ({ ...prev, cards: [...prev.cards, card] }));
  const addWallet = (wallet: Wallet) => setState(prev => ({ ...prev, wallets: [...prev.wallets, wallet] }));
  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...prev.assets, asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...prev.liabilities, liability] }));

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const amount = transaction.amount;
    const delta = (transaction.type === 'Income' || transaction.type === 'Liability') ? amount : -amount;
    const finalDelta = delta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = newState.banks.map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.cards = newState.cards.map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = newState.wallets.map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.liabilities = newState.liabilities.map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = newState.incomes.filter(i => i.id !== transaction.id);
      newState.expenses = newState.expenses.filter(e => e.id !== transaction.id);
      newState.assets = newState.assets.filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = newState.liabilities.filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const sharedAmt = transaction.sharedAmount || 0;
      const selfAmt = transaction.amount - sharedAmt;

      switch (transaction.type) {
        case 'Income':
          if (selfAmt > 0) {
            newState.incomes.push({ id: transaction.id, name: transaction.description, amount: selfAmt, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          }
          if (transaction.isShared && transaction.sharedContacts) {
            transaction.sharedContacts.forEach((contact, idx) => {
              newState.liabilities.push({ id: `${transaction.id}_shared_${idx}`, name: `Payable: ${contact.name} (Ref: ${transaction.description})`, amount: contact.amount, type: 'Payable', ownerId: transaction.ownerId });
            });
          }
          break;
        case 'Expense':
          if (selfAmt > 0) {
            newState.expenses.push({ id: transaction.id, category: transaction.category || 'Others', amount: selfAmt, date: transaction.date, ownerId: transaction.ownerId });
          }
          if (transaction.isShared && transaction.sharedContacts) {
            transaction.sharedContacts.forEach((contact, idx) => {
              newState.assets.push({ id: `${transaction.id}_shared_${idx}`, name: `Receivable: ${contact.name} (Ref: ${transaction.description})`, value: contact.amount, type: 'Receivable', ownerId: transaction.ownerId });
            });
          }
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: transaction.description, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: transaction.description, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...prev.transactions] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = prev.transactions.find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: prev.transactions.filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = prev.transactions.find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = newState.transactions.map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const filteredState = useMemo(() => {
    // If selecting specific members (or "Me")
    const isFiltered = activeMemberIds.length > 0 && !activeMemberIds.includes('all');

    if (!isFiltered && activeMemberIds.includes('all')) {
      return state; // All family view
    }

    // Default to "Me" if selection is empty
    const filterIds = activeMemberIds.length === 0 ? [undefined, ''] : activeMemberIds;

    const filterFn = (item: any) => {
      // ownerId undefined or empty string represents the main user
      const ownerId = item.ownerId || '';
      return filterIds.includes(ownerId) || (filterIds.includes('') && ownerId === undefined);
    };

    return {
      ...state,
      banks: state.banks.filter(filterFn),
      cards: state.cards.filter(filterFn),
      wallets: state.wallets.filter(filterFn),
      incomes: state.incomes.filter(filterFn),
      expenses: state.expenses.filter(filterFn),
      assets: state.assets.filter(filterFn),
      liabilities: state.liabilities.filter(filterFn),
      transactions: state.transactions.filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = () => {
    setState(initialState);
    setAuthenticated(false);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember,
      addBank, addCard, addWallet, addIncome, addExpense, addAsset, addLiability,
      addTransaction, updateTransaction, deleteTransaction, resetBoarding 
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding } = useFinance();
  const [showFilter, setShowFilter] = useState(false);

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'transactions', label: 'Transactions', icon: '💸' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'statements', label: 'Balance Sheet & P&L', icon: '📑' },
    { id: 'profile', label: 'Profile', icon: '👤' },
  ];

  const toggleSelection = (id: string) => {
    if (id === 'all') {
      setActiveMemberIds(['all']);
      return;
    }

    let newIds = [...activeMemberIds].filter(i => i !== 'all');
    if (newIds.includes(id)) {
      newIds = newIds.filter(i => i !== id);
    } else {
      newIds.push(id);
    }
    setActiveMemberIds(newIds);
  };

  const getActiveLabel = () => {
    if (activeMemberIds.includes('all')) return "Family View";
    if (activeMemberIds.length === 0) return "Individual View";
    if (activeMemberIds.length === 1 && activeMemberIds[0] === '') return "Individual View";
    return `Selected Individuals (${activeMemberIds.length})`;
  };

