      <aside className="w-full md:w-64 bg-white border-r border-slate-200 shadow-sm z-30 flex flex-col">
        <div className="p-6">
          <h1 className="text-2xl font-bold text-indigo-600 flex items-center gap-2">
            <span className="text-3xl">💎</span> WealthFlow
          </h1>
        </div>
        <nav className="flex-1 mt-4 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
                activeTab === item.id 
                  ? 'bg-indigo-50 text-indigo-700' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}
          <button
            onClick={resetBoarding}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium text-rose-600 hover:bg-rose-50 transition-colors mt-8"
          >
            <span>🔄</span> Reset Data
          </button>
        </nav>

        <div className="p-4 border-t border-slate-100 bg-white">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold">
              {state.profile?.name?.charAt(0) || '?'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-slate-800 truncate">{state.profile?.name}</p>
              <p className="text-xs text-slate-500 truncate">{state.profile?.designation}</p>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative">
        <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-4 z-40 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-semibold text-slate-800 capitalize">
              {activeTab.replace('-', ' ')}
            </h2>
          </div>

          <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl border border-slate-200 shadow-sm">
            <button 
              onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }}
              className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${currentView === 'me' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Me
            </button>
            <button 
              onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }}
              className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Family
            </button>
            {familyMembers.length > 0 && (
              <div className="relative">
                <button 
                  onClick={() => setShowMemberSelector(!showMemberSelector)}
                  className={`px-4 py-2 rounded-xl text-xs font-bold transition-all flex items-center gap-2 ${currentView === 'custom' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Custom
                  <span className={`text-[10px] transition-transform ${showMemberSelector ? 'rotate-180' : ''}`}>▼</span>
                </button>

                {showMemberSelector && (
                  <>
                    <div className="fixed inset-0 z-40" onClick={() => setShowMemberSelector(false)}></div>
                    <div className="absolute right-0 mt-3 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 p-4 animate-in fade-in slide-in-from-top-2 duration-200">
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Select Members</p>
                      <div className="space-y-1 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
                        <button 
                          onClick={() => toggleMember('')}
                          className={`w-full text-left px-3 py-2.5 rounded-xl text-sm font-medium flex justify-between items-center ${activeMemberIds.includes('') ? 'bg-indigo-50 text-indigo-600' : 'text-slate-600 hover:bg-slate-50'}`}
                        >
                          👤 Me
                          {activeMemberIds.includes('') && <span className="text-indigo-600 font-bold">✓</span>}
                        </button>
                        {familyMembers.map(member => (
                          <button 
                            key={member.id}
                            onClick={() => toggleMember(member.id)}
                            className={`w-full text-left px-3 py-2.5 rounded-xl text-sm font-medium flex justify-between items-center ${activeMemberIds.includes(member.id) ? 'bg-indigo-50 text-indigo-600' : 'text-slate-600 hover:bg-slate-50'}`}
                          >
                            👨‍👩‍👧 {member.name}
                            {activeMemberIds.includes(member.id) && <span className="text-indigo-600 font-bold">✓</span>}
                          </button>
                        ))}
                      </div>
                    </div>
                  </>
                )}
              </div>
            )}
          </div>

          <div className="hidden lg:flex items-center gap-4">
             <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">Status</span>
                <span className="text-[9px] font-bold text-green-500 uppercase">Live Sync</span>
             </div>
             <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
          </div>
        </header>
        <div className="p-8 max-w-7xl mx-auto pb-24">
          {children}
        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!formData.isShared) return;
    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const allAccounts = useMemo(() => [
    ...(state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId })),
    ...(state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId })),
    ...(state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId })),
    ...(state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }))
  ], [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Permanently delete this entry? Associated balances will be recalculated.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Please select a funding source."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    try {
      if (editingId) updateTransaction(transactionData);
      else addTransaction(transactionData);
      setShowModal(false);
    } catch (err) { alert("Failed to record transaction."); }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percent', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjust', icon: '➕' },
  ];

  const familyMembers = state.profile?.familyMembers || [];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl font-bold text-slate-800">Financial Ledger</h3>
          <p className="text-sm text-slate-500 italic">Showing activities for current view context.</p>
        </div>
        <div className="grid grid-cols-2 sm:flex items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg flex items-center justify-center gap-2">💰 Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-5 py-3 bg-rose-600 text-white rounded-xl font-bold hover:bg-rose-700 transition-all shadow-lg flex items-center justify-center gap-2">📉 Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-5 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg flex items-center justify-center gap-2">🏗️ Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-5 py-3 bg-amber-600 text-white rounded-xl font-bold hover:bg-amber-700 transition-all shadow-lg flex items-center justify-center gap-2">🧾 Debt</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Item Details</th>
                <th className="px-6 py-5">Owner</th>
                <th className="px-6 py-5">Account Used</th>
                <th className="px-6 py-5 text-right">Value</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 font-semibold text-slate-600 text-sm whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-100 text-indigo-700 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-tighter shadow-sm border border-indigo-200">Shared</span>}
                      </div>
                      <div className="flex flex-col">
                        {t.category && <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{t.category}</span>}
                        {t.isShared && (
                          <span className="text-[9px] text-indigo-400 italic font-medium">Split with {t.numberOfPeople} people</span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-2.5 py-1 rounded-full uppercase border border-indigo-100">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <div className="flex items-center gap-2">
                         <span className="text-xs text-slate-600 font-medium">{account?.name || 'Manual'}</span>
                         <span className="text-[9px] text-slate-400 font-mono bg-slate-100 px-1 py-0.5 rounded uppercase">{account?.type || 'Record'}</span>
                       </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all" title="Edit Entry">✏️</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-lg transition-all" title="Delete Entry">🗑️</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-6 py-24 text-center">
                    <div className="flex flex-col items-center gap-3 opacity-25">
                      <span className="text-5xl">📂</span>
                      <p className="text-slate-500 font-medium italic">No transactions found for the current selection.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Modify Record' : `New ${formData.type}`}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 font-bold p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Responsible Member</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                    <option value="">Me (Default)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.relation})</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Payment Method</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Choose Account</option>
                    {allAccounts.filter(a => !formData.ownerId || a.ownerId === formData.ownerId || !a.ownerId).map(acc => (
                      <option key={acc.id} value={acc.id}>{acc.name} ({getOwnerName(acc.ownerId)})</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Amount ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-lg" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Effective Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              {(formData.type === 'Income' || formData.type === 'Expense') && (
                <div className="p-6 bg-indigo-50/50 rounded-3xl border border-indigo-100 space-y-5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <span className="text-xl">🤝</span>
                      <label className="text-[11px] font-bold text-indigo-700 uppercase tracking-widest">Shared with Others?</label>
                    </div>
                    <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${formData.isShared ? 'bg-indigo-600 shadow-md shadow-indigo-100' : 'bg-slate-200'}`}>
                      <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isShared ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 pt-3 animate-in fade-in slide-in-from-top-4 duration-300">
                       <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Include Owner in Split?</label>
                          <div className="flex items-center gap-3 bg-white p-3 border border-slate-200 rounded-xl shadow-sm">
                            <input type="checkbox" className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" checked={formData.includeSelf} onChange={e => setFormData({ ...formData, includeSelf: e.target.checked })} />
                            <span className="text-xs font-bold text-slate-600">{formData.includeSelf ? 'Owner Participates' : 'Others Only'}</span>
                          </div>
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Total Group Size</label>
                          <input required type="number" min={formData.includeSelf ? "2" : "1"} className="w-full p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={formData.totalParticipants} onChange={e => setFormData({ ...formData, totalParticipants: e.target.value })} />
                        </div>
                      </div>

                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Division Method</label>
                        <div className="flex flex-wrap gap-2">
                          {splitOptions.map(opt => (
                            <button
                              key={opt.id}
                              type="button"
                              onClick={() => setFormData({ ...formData, splitType: opt.id })}
                              className={`flex-1 min-w-[90px] px-3 py-2.5 rounded-xl text-[10px] font-bold border transition-all flex items-center justify-center gap-2 ${
                                formData.splitType === opt.id ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-200'
