const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', onCancel: () => void }> = ({ type, onCancel }) => {
  const { addBank, addCard, addWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>({
    ownerId: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });
  const currency = state.profile.currency;
  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      addBank({ ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance) });
    } else if (type === 'card') {
      addCard({ 
        ...commonProps,
        lenderName: formData.lender, 
        balance: Number(formData.balance), 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined,
        offers: formData.offers
      });
    } else if (type === 'wallet') {
      addWallet({ ...commonProps, name: formData.name, balance: Number(formData.balance) });
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Holder</label>
        <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">Me (Individual)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.relation})</option>)}
        </select>
      </div>

      {type === 'bank' && (
        <>
          <input required placeholder="Bank Name" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
          <input placeholder="Account Number (Optional)" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" onChange={e => setFormData({...formData, accNum: e.target.value})} />
          <input required type="number" placeholder={`Opening Balance (${currency})`} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold" onChange={e => setFormData({...formData, balance: e.target.value})} />
        </>
      )}
      {type === 'card' && (
        <>
          <input required placeholder="Lender Name" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" onChange={e => setFormData({...formData, lender: e.target.value})} />
          <input required type="number" placeholder={`Opening Balance (${currency})`} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold" onChange={e => setFormData({...formData, balance: e.target.value})} />
          <input required maxLength={4} placeholder="Card Ending With (Last 4 digits)" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" onChange={e => setFormData({...formData, last4: e.target.value})} />
          <input type="number" placeholder={`Spend Limit (${currency})`} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" onChange={e => setFormData({...formData, limit: e.target.value})} />
          <div className="space-y-2">
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Offers</p>
            <div className="grid grid-cols-2 gap-2">
               {['movie', 'dining', 'concierge', 'lounge'].map(off => (
                 <label key={off} className="flex items-center gap-2 text-sm text-slate-600">
                   <input type="checkbox" className="rounded text-indigo-600" onChange={e => setFormData({...formData, offers: {...formData.offers, [off]: e.target.checked}})} />
                   {off.charAt(0).toUpperCase() + off.slice(1)}
                 </label>
               ))}
            </div>
          </div>
        </>
      )}
      {type === 'wallet' && (
        <>
          <input required placeholder="Wallet Name" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
          <input required type="number" placeholder={`Opening Balance (${currency})`} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold" onChange={e => setFormData({...formData, balance: e.target.value})} />
        </>
      )}
      <div className="flex gap-4 pt-4">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors">Cancel</button>
        <button type="submit" className="flex-1 px-4 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">Save</button>
