export const calculateRates = (state: FinancialState) => {
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1, 0, 0, 0);

  const elapsedMs = now.getTime() - startOfMonth.getTime();
  const hoursPassed = Math.max(1, elapsedMs / (1000 * 60 * 60));

  const currentMonthIncome = (state.transactions || [])
    .filter(t => t.type === 'Income' && new Date(t.date) >= startOfMonth)
    .reduce((acc, t) => acc + t.amount, 0);

  const currentMonthExpense = (state.transactions || [])
    .filter(t => t.type === 'Expense' && new Date(t.date) >= startOfMonth)
    .reduce((acc, t) => acc + t.amount, 0);

  return {
    earningsPerHour: currentMonthIncome / hoursPassed,
    spendingPerHour: currentMonthExpense / hoursPassed,
    monthlySurplus: currentMonthIncome - currentMonthExpense
  };
};

export const calculateNetWorth = (state: FinancialState) => {
  const manualAssets = (state.assets || []).reduce((acc, a) => acc + a.value, 0);
  const bankBalances = (state.banks || []).reduce((acc, b) => acc + b.balance, 0);
  const walletBalances = (state.wallets || []).reduce((acc, w) => acc + w.balance, 0);

  const manualLiabilities = (state.liabilities || []).reduce((acc, l) => acc + l.amount, 0);
  const cardBalances = (state.cards || []).reduce((acc, c) => acc + c.balance, 0);

  const totalAssets = manualAssets + bankBalances + walletBalances;
  const totalLiabilities = manualLiabilities + cardBalances;

  return {
    assets: totalAssets,
    liabilities: totalLiabilities,
    netWorth: totalAssets - totalLiabilities,
    breakdown: {
      manualAssets,
      bankBalances,
      walletBalances,
      manualLiabilities,
      cardBalances
    }
  };
};

export const getTransactionsForPeriod = (transactions: Transaction[], days: number) => {
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - days);
  return (transactions || []).filter(t => new Date(t.date) >= cutoff);
};

