import React, { useState, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  const toggleMember = (id: string) => {
    let current = activeMemberIds.includes('all') ? [] : [...activeMemberIds];
    if (current.includes(id)) {
      current = current.filter(i => i !== id);
    } else {
      current.push(id);
    }
    setActiveMemberIds(current);
  };

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'transactions', label: 'Transactions', icon: '💸' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'statements', label: 'Balance Sheet & P&L', icon: '📑' },
    { id: 'profile', label: 'Profile', icon: '👤' },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      <aside className="w-full md:w-64 bg-white border-r border-slate-200 shadow-sm z-30 flex flex-col">
        <div className="p-6">
          <h1 className="text-2xl font-bold text-indigo-600 flex items-center gap-2">
            <span className="text-3xl">💎</span> WealthFlow
          </h1>
        </div>
        <nav className="flex-1 mt-4 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
                activeTab === item.id ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}
          <button
            onClick={resetBoarding}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium text-rose-600 hover:bg-rose-50 transition-colors mt-8"
          >
            <span>🔄</span> Reset Local Data
          </button>
        </nav>

        <div className="p-6 border-t border-slate-100">
           <div className="p-4 bg-indigo-50 rounded-2xl">
             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-1">Current Sync ID</p>
             <p className="text-xs font-bold text-indigo-700 truncate">{state.profile?.mobileNumber || 'Not Linked'}</p>
           </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative">
        <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-4 z-40 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-semibold text-slate-800 capitalize">
              {navItems.find(i => i.id === activeTab)?.label || activeTab}
            </h2>
            <button 
              onClick={handleSync}
              disabled={isSyncing}
              className={`flex items-center gap-2 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-sm ${
                isSyncing ? 'bg-slate-100 text-slate-400' : 'bg-emerald-600 text-white hover:bg-emerald-700 active:scale-95'
              }`}
            >
              <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
              {isSyncing ? 'Retrieving Data...' : 'Sync Family Data'}
            </button>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl border border-slate-200 shadow-sm">
              <button 
                onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }}
                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${currentView === 'me' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
              > Individual </button>
              <button 
                onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }}
                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
              > Consolidated </button>
              {familyMembers.length > 0 && (
                <div className="relative">
                  <button 
                    onClick={() => setShowMemberSelector(!showMemberSelector)}
                    className={`px-4 py-2 rounded-xl text-xs font-bold transition-all flex items-center gap-2 ${currentView === 'custom' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-slate-200' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    Custom <span className="text-[8px] transition-transform duration-200" style={{ transform: showMemberSelector ? 'rotate(180deg)' : 'none' }}>▼</span>
                  </button>
                  {showMemberSelector && (
                    <div className="absolute right-0 mt-3 w-56 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 p-3 animate-in fade-in slide-in-from-top-2">
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 px-2">Select Members</p>
                      <div className="space-y-1">
                        {familyMembers.map(member => (
                          <button key={member.id} onClick={() => toggleMember(member.id)} className={`w-full text-left px-3 py-2 rounded-xl text-sm font-medium flex justify-between items-center transition-colors ${activeMemberIds.includes(member.id) ? 'bg-indigo-50 text-indigo-600 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}>
                            {member.name} {activeMemberIds.includes(member.id) && '✓'}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>

            <div className="relative">
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="relative p-2.5 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 shadow-sm transition-all active:scale-95"
              >
                <span>🔔</span>
                {unreadCount > 0 && (
                  <span className="absolute -top-1.5 -right-1.5 bg-rose-500 text-white text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center animate-bounce border-2 border-white shadow-sm">
                    {unreadCount}
                  </span>
                )}
              </button>
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-sm font-bold text-slate-800">Sync Activity</h4>
                    <button onClick={clearNotifications} className="text-[10px] font-black text-indigo-600 hover:underline uppercase tracking-widest">Clear All</button>
                  </div>
                  <div className="max-h-[32rem] overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-60' : 'bg-indigo-50/10'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-xs font-black text-slate-800">{n.title}</p>
                          <span className="text-[8px] font-black text-slate-400 uppercase">{n.timestamp}</span>
                        </div>
                        <p className="text-[11px] text-slate-600 leading-normal font-medium">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-12 text-center text-slate-400 italic text-xs">No recent sync activity</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>
        <div className="p-8 max-w-7xl mx-auto pb-24">
          {children}
        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
      `}</style>
    </div>
  );
};

