                  <button onClick={() => setViewingHistory(wallet)} className="text-[8px] font-black uppercase text-indigo-600 hover:underline">History</button>
                </div>
              </div>
            </div>
          ))}
          {(!filteredState.wallets || filteredState.wallets.length === 0) && <p className="text-slate-400 text-sm col-span-full italic">No wallet balances in view.</p>}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-slate-900 mb-6">{editingAccount ? 'Edit' : 'Add New'} {showModal}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}

      {viewingHistory && (
        <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    accountType: 'Savings',
    customAccountType: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { 
        ...commonProps, 
        name: formData.name, 
        accountNumber: formData.accNum, 
        balance: Number(formData.balance),
        accountType: formData.accountType,
        customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined
      };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { 
        ...commonProps,
        lenderName: formData.name, 
        balance: Number(formData.balance), 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined,
        offers: formData.offers
      };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Holder</label>
        <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">Me (Individual)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.relation})</option>)}
        </select>
      </div>

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">{type === 'card' ? 'Lender' : 'Name'}</label>
        <input required placeholder={type === 'card' ? 'Lender Name' : 'Bank/Wallet Name'} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>

      {type === 'bank' && (
        <>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Type</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.accountType} onChange={e => setFormData({...formData, accountType: e.target.value})}>
                <option value="Savings">Savings</option>
                <option value="Current">Current</option>
                <option value="Salary">Salary</option>
                <option value="Others">Others</option>
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Number</label>
              <input placeholder="Optional" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.accNum} onChange={e => setFormData({...formData, accNum: e.target.value})} />
            </div>
          </div>
          {formData.accountType === 'Others' && (
            <div className="space-y-1 animate-in slide-in-from-top-2">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Specify Account Type</label>
              <input required placeholder="e.g. Fixed Deposit, Provident Fund" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.customAccountType} onChange={e => setFormData({...formData, customAccountType: e.target.value})} />
            </div>
          )}
        </>
      )}

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Current Balance</label>
        <input required type="number" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
      </div>

      {type === 'card' && (
        <>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Last 4 Digits</label>
              <input required maxLength={4} placeholder="1234" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value})} />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Limit</label>
              <input type="number" placeholder="Optional" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.limit} onChange={e => setFormData({...formData, limit: e.target.value})} />
            </div>
          </div>
          <div className="space-y-2">
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Offers</p>
            <div className="grid grid-cols-2 gap-2">
               {['movie', 'dining', 'concierge', 'lounge'].map(off => (
                 <label key={off} className="flex items-center gap-2 text-sm text-slate-600">
                   <input type="checkbox" className="rounded text-indigo-600" checked={formData.offers[off]} onChange={e => setFormData({...formData, offers: {...formData.offers, [off]: e.target.checked}})} />
                   {off.charAt(0).toUpperCase() + off.slice(1)}
                 </label>
               ))}
            </div>
          </div>
        </>
      )}

      <div className="flex gap-4 pt-4">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors">Cancel</button>
        <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">Save Account</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();

  // Default range: last 10 days
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);

  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-2xl rounded-[2rem] p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">Statement: {account.name || account.lenderName}</h3>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Transaction History & Ledger</p>
          </div>
          <button onClick={onClose} className="p-2 bg-slate-50 text-slate-400 hover:text-slate-600 rounded-full transition-all">✕</button>
        </div>

        <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 mb-8 flex flex-wrap gap-6 items-end">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Period From</label>
            <input type="date" className="p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Period To</label>
            <input type="date" className="p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="flex-1 text-right">
             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Net Change</p>
             <p className={`text-xl font-black ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
          {history.length > 0 ? (
            <div className="space-y-3">
              {history.map(t => (
                <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-2xl flex items-center justify-between hover:border-indigo-100 transition-all group">
                   <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg ${t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {t.type === 'Income' ? '💰' : '📉'}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.date} • {t.category || 'General'}</p>
                      </div>
                   </div>
                   <p className={`font-black ${t.type === 'Income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                     {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                   </p>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-20 opacity-30 italic text-slate-500">No transactions recorded for the selected range.</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Accounts;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string; // Used for "syncing"
  canAddTransactions?: boolean; // New: Permission toggle
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string; // undefined means the main user
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; // Added: Annual spending limit
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[]; // New: For tracking family activity
}

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard } from '../types';

const Accounts: React.FC = () => {
  const { filteredState, state } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Unknown';
  };

  const calculateAnnualSpend = (cardId: string) => {
    const currentYear = new Date().getFullYear();
    return (filteredState.transactions || [])
      .filter(t => t.accountId === cardId && t.type === 'Expense' && new Date(t.date).getFullYear() === currentYear)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <section>
        <div className="flex justify-between items-center mb-6">
          <div className="flex flex-col">
            <h3 className="text-xl font-bold text-slate-800">Bank Accounts</h3>
            <p className="text-xs text-slate-400">Opening balances are tracked as assets.</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('bank'); }}
            className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors"
          >
            + Add Bank
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm relative group hover:shadow-md transition-shadow">
              <span className="absolute top-4 right-4 text-[8px] font-black uppercase text-indigo-400 bg-indigo-50 px-1.5 py-0.5 rounded">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-indigo-50 rounded-xl text-xl">🏦</div>
                <div className="text-right">
                  <p className="text-xs text-slate-400 font-bold uppercase">Balance</p>
                  <p className="text-lg font-bold text-slate-800">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="flex flex-col mb-1">
                 <h4 className="font-bold text-slate-800 leading-tight">{bank.name}</h4>
                 <span className="text-[10px] font-black uppercase text-indigo-400">
                    {bank.accountType === 'Others' ? bank.customAccountType : bank.accountType}
                 </span>
              </div>
              <p className="text-sm text-slate-500 mb-4">{bank.accountNumber || 'Checking Account'}</p>
              <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity pt-2 border-t border-slate-50">
                <button onClick={() => handleEdit('bank', bank)} className="text-[10px] font-black uppercase text-indigo-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[10px] font-black uppercase text-indigo-600 hover:underline">History</button>
              </div>
            </div>
          ))}
          {(!filteredState.banks || filteredState.banks.length === 0) && <p className="text-slate-400 text-sm col-span-full italic">No bank accounts in current view.</p>}
        </div>
      </section>

      <section>
        <div className="flex justify-between items-center mb-6">
          <div className="flex flex-col">
            <h3 className="text-xl font-bold text-slate-800">Credit Cards</h3>
            <p className="text-xs text-slate-400">Outstanding balances are tracked as liabilities.</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('card'); }}
            className="px-4 py-2 bg-slate-800 text-white rounded-lg text-sm font-medium hover:bg-slate-900 transition-colors"
          >
            + Add Card
          </button>
        </div>
