          {(filteredState.cards || []).map(card => {
            const annualUsed = calculateAnnualSpend(card.id);
            const annualLimit = card.annualLimit || 0;
            const spendPercentage = annualLimit > 0 ? (annualUsed / annualLimit) * 100 : 0;

            return (
              <div key={card.id} className="relative overflow-hidden bg-gradient-to-br from-slate-800 to-slate-900 p-8 rounded-2xl text-white shadow-xl group flex flex-col justify-between">
                <span className="absolute top-4 right-4 text-[8px] font-black uppercase text-white/40 bg-white/5 px-1.5 py-0.5 rounded border border-white/10">{getOwnerName(card.ownerId)}</span>
                <div className="relative z-10">
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <p className="text-xs opacity-60 font-bold uppercase tracking-widest">Outstanding</p>
                      <p className="text-3xl font-bold">{formatCurrency(card.balance, currency)}</p>
