                          className={`h-full transition-all duration-1000 ${spendPercentage > 90 ? 'bg-rose-500' : spendPercentage > 75 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                          style={{ width: `${Math.min(100, spendPercentage)}%` }} 
                        />
                      </div>
                      <div className="flex justify-between items-center">
                        <p className="text-[10px] font-bold opacity-60">{formatCurrency(annualUsed, currency)} used</p>
                        <p className="text-[10px] font-bold opacity-60">Limit: {formatCurrency(annualLimit, currency)}</p>
                      </div>
                    </div>
                  )}
                </div>

                <div className="relative z-10 mt-4 flex justify-between items-end">
                  <p className="font-mono tracking-widest opacity-80">**** **** **** {card.last4}</p>
                  <div className="flex gap-4">
                    <button onClick={() => handleEdit('card', card)} className="text-[10px] font-black uppercase text-white/40 hover:text-white transition-colors">Edit</button>
                    <button onClick={() => setViewingHistory(card)} className="text-[10px] font-black uppercase text-white/40 hover:text-white transition-colors">History</button>
                  </div>
                </div>
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>
              </div>
            );
          })}
          {(!filteredState.cards || filteredState.cards.length === 0) && <p className="text-slate-400 text-sm col-span-full italic">No credit cards in current view.</p>}
        </div>
      </section>

      <section>
        <div className="flex justify-between items-center mb-6">
          <div className="flex flex-col">
            <h3 className="text-xl font-bold text-slate-800">Wallets & Digital Cash</h3>
            <p className="text-xs text-slate-400">Stored balances are tracked as assets.</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('wallet'); }}
            className="px-4 py-2 border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors"
          >
            + Add Wallet
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {(filteredState.wallets || []).map(wallet => (
            <div key={wallet.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex items-center gap-4 relative group hover:shadow-md transition-shadow">
              <span className="absolute top-1 right-2 text-[6px] font-black uppercase text-slate-300">{getOwnerName(wallet.ownerId)}</span>
              <div className="w-10 h-10 rounded-lg bg-orange-50 text-orange-600 flex items-center justify-center text-xl">📱</div>
              <div className="flex-1">
                <h4 className="text-sm font-bold text-slate-800">{wallet.name}</h4>
                <p className="text-lg font-bold text-indigo-600">{formatCurrency(wallet.balance, currency)}</p>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity pt-1 border-t border-slate-50 mt-1">
                  <button onClick={() => handleEdit('wallet', wallet)} className="text-[8px] font-black uppercase text-indigo-600 hover:underline">Edit</button>
                  <button onClick={() => setViewingHistory(wallet)} className="text-[8px] font-black uppercase text-indigo-600 hover:underline">History</button>
                </div>
              </div>
            </div>
          ))}
          {(!filteredState.wallets || filteredState.wallets.length === 0) && <p className="text-slate-400 text-sm col-span-full italic">No wallet balances in view.</p>}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-slate-900 mb-6">{editingAccount ? 'Edit' : 'Add New'} {showModal}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}

      {viewingHistory && (
        <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { 
        ...commonProps, 
        name: formData.name, 
        accountNumber: formData.accNum, 
        balance: Number(formData.balance),
        accountType: formData.accountType,
        customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined
      };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { 
        ...commonProps,
        lenderName: formData.name, 
        balance: Number(formData.balance), 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined,
        annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined,
        offers: formData.offers
      };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Holder</label>
        <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">Me (Individual)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name} ({m.relation})</option>)}
        </select>
      </div>

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">{type === 'card' ? 'Lender' : 'Name'}</label>
        <input required placeholder={type === 'card' ? 'Lender Name' : 'Bank/Wallet Name'} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>

      {type === 'bank' && (
        <>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Type</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.accountType} onChange={e => setFormData({...formData, accountType: e.target.value})}>
                <option value="Savings">Savings</option>
                <option value="Current">Current</option>
                <option value="Salary">Salary</option>
                <option value="Others">Others</option>
              </select>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Number</label>
              <input placeholder="Optional" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.accNum} onChange={e => setFormData({...formData, accNum: e.target.value})} />
            </div>
          </div>
          {formData.accountType === 'Others' && (
            <div className="space-y-1 animate-in slide-in-from-top-2">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Specify Account Type</label>
              <input required placeholder="e.g. Fixed Deposit, Provident Fund" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium" value={formData.customAccountType} onChange={e => setFormData({...formData, customAccountType: e.target.value})} />
            </div>
          )}
        </>
      )}

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Current Balance</label>
        <input required type="number" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
      </div>

      {type === 'card' && (
        <>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Last 4 Digits</label>
              <input required maxLength={4} placeholder="1234" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value})} />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Credit Limit</label>
              <input type="number" placeholder="Optional" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-medium" value={formData.limit} onChange={e => setFormData({...formData, limit: e.target.value})} />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest block">Annual Spend Limit</label>
            <input 
              type="number" 
              placeholder="Set yearly target limit" 
              className="w-full p-3 bg-indigo-50/50 border border-indigo-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" 
              value={formData.annualLimit} 
              onChange={e => setFormData({...formData, annualLimit: e.target.value})} 
            />
            <p className="text-[8px] text-slate-400 italic">Tracking starts from January 1st of the current year.</p>
          </div>
          <div className="space-y-2">
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Offers</p>
            <div className="grid grid-cols-2 gap-2">
               {['movie', 'dining', 'concierge', 'lounge'].map(off => (
                 <label key={off} className="flex items-center gap-2 text-sm text-slate-600">
                   <input type="checkbox" className="rounded text-indigo-600" checked={formData.offers[off]} onChange={e => setFormData({...formData, offers: {...formData.offers, [off]: e.target.checked}})} />
                   {off.charAt(0).toUpperCase() + off.slice(1)}
                 </label>
               ))}
            </div>
          </div>
        </>
      )}

      <div className="flex gap-4 pt-4">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors">Cancel</button>
        <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">Save Account</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();

  // Default range: last 10 days
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);

  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-2xl rounded-[2rem] p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">Statement: {account.name || account.lenderName}</h3>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mt-1">Transaction History & Ledger</p>
          </div>
          <button onClick={onClose} className="p-2 bg-slate-50 text-slate-400 hover:text-slate-600 rounded-full transition-all">✕</button>
        </div>

        <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 mb-8 flex flex-wrap gap-6 items-end">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Period From</label>
            <input type="date" className="p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Period To</label>
            <input type="date" className="p-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="flex-1 text-right">
             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Net Change</p>
             <p className={`text-xl font-black ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
          {history.length > 0 ? (
            <div className="space-y-3">
              {history.map(t => (
                <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-2xl flex items-center justify-between hover:border-indigo-100 transition-all group">
                   <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg ${t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {t.type === 'Income' ? '💰' : '📉'}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{t.description}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.date} • {t.category || 'General'}</p>
                      </div>
                   </div>
                   <p className={`font-black ${t.type === 'Income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                     {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                   </p>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-20 opacity-30 italic text-slate-500">No transactions recorded for the selected range.</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Accounts;

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const memberSelectorRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);

  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (memberSelectorRef.current && !memberSelectorRef.current.contains(event.target as Node)) {
        setShowMemberSelector(false);
      }
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const toggleMember = (id: string) => {
    let current = activeMemberIds.includes('all') ? [] : [...activeMemberIds];
    if (current.includes(id)) {
      current = current.filter(i => i !== id);
    } else {
      current.push(id);
    }
    setActiveMemberIds(current);
  };

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'DASHBOARD', icon: '📊' },
    { id: 'transactions', label: 'LEDGER', icon: '💸' },
    { id: 'accounts', label: 'PORTFOLIO', icon: '🏦' },
    { id: 'statements', label: 'STATEMENTS', icon: '📑' },
    { id: 'profile', label: 'PROFILE', icon: '👤' },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white">
      {/* Dark Sidebar - Luxury Contrast */}
      <aside className="w-full md:w-72 bg-black border-r border-white/10 z-30 flex flex-col text-white">
        <div className="p-8">
          <h1 className="text-xl font-black tracking-tighter flex items-center gap-2">
            WEALTHFLOW
          </h1>
          <p className="text-[10px] font-bold text-white/40 tracking-[0.4em] mt-1">PRIVATE SUITE</p>
        </div>

        <nav className="flex-1 mt-4 px-6 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-none text-[11px] font-black tracking-widest transition-all border-l-4 ${
                activeTab === item.id 
                  ? 'bg-white/10 border-white text-white' 
                  : 'border-transparent text-white/50 hover:text-white hover:bg-white/5'
              }`}
            >
              <span className="text-lg opacity-70">{item.icon}</span>
              {item.label}
            </button>
          ))}

          <div className="pt-10">
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-4 rounded-none text-[10px] font-black tracking-widest text-white/30 hover:text-rose-400 transition-colors uppercase"
            >
              <span>🔄</span> Reset Workspace
            </button>
          </div>
        </nav>

        <div className="p-8 border-t border-white/5">
           <div className="p-5 bg-white/5 border border-white/10 rounded-2xl">
             <p className="text-[9px] font-black text-white/30 uppercase tracking-widest mb-1">CLIENT ACCESS ID</p>
             <p className="text-xs font-mono text-white/80 truncate tracking-tight">{state.profile?.mobileNumber || 'OFFLINE'}</p>
           </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative flex flex-col">
        {/* Minimalist White Header */}
        <header className="sticky top-0 bg-white/90 backdrop-blur-xl border-b border-black/5 px-8 py-5 z-40 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-6">
            <h2 className="text-sm font-black text-black uppercase tracking-[0.3em]">
              {navItems.find(i => i.id === activeTab)?.label || activeTab}
            </h2>
            <button 
              onClick={handleSync}
              disabled={isSyncing}
              className={`flex items-center gap-2 px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all border ${
                isSyncing ? 'bg-slate-50 text-slate-400 border-slate-200' : 'bg-black text-white hover:bg-slate-800 active:scale-95 border-black shadow-lg shadow-black/10'
              }`}
            >
              <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
              {isSyncing ? 'UPDATING...' : 'SYNC ASSETS'}
            </button>
          </div>

          <div className="flex items-center gap-5">
            <div className="flex items-center gap-1 bg-slate-50 p-1 border border-black/5 rounded-full">
              <button 
                onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }}
                className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${currentView === 'me' ? 'bg-white text-black shadow-sm ring-1 ring-black/5' : 'text-slate-400 hover:text-black'}`}
              > SELF </button>
              <button 
                onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }}
                className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${currentView === 'family' ? 'bg-white text-black shadow-sm ring-1 ring-black/5' : 'text-slate-400 hover:text-black'}`}
              > FAMILY </button>

              <div className="relative" ref={memberSelectorRef}>
                <button 
                  onClick={() => setShowMemberSelector(!showMemberSelector)}
                  className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${currentView === 'custom' ? 'bg-white text-black shadow-sm ring-1 ring-black/5' : 'text-slate-400 hover:text-black'}`}
                >
                  CUSTOM <span className="text-[8px] transition-transform duration-200" style={{ transform: showMemberSelector ? 'rotate(180deg)' : 'none' }}>▼</span>
                </button>
                {showMemberSelector && (
                  <div className="absolute right-0 mt-4 w-60 bg-white border border-black/5 rounded-2xl shadow-2xl z-50 p-4 animate-in fade-in slide-in-from-top-2 luxury-shadow">
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] mb-3 px-1">ACCESS PERMISSION</p>
                    <div className="space-y-1">
                      <button 
                        onClick={() => toggleMember('')} 
                        className={`w-full text-left px-4 py-3 rounded-xl text-xs font-black uppercase tracking-widest flex justify-between items-center transition-all ${activeMemberIds.includes('') ? 'bg-black text-white' : 'text-slate-600 hover:bg-slate-50'}`}
                      >
                        INDIVIDUAL {activeMemberIds.includes('') && '✓'}
                      </button>

                      {familyMembers.map(member => (
                        <button 
                          key={member.id} 
                          onClick={() => toggleMember(member.id)} 
                          className={`w-full text-left px-4 py-3 rounded-xl text-xs font-black uppercase tracking-widest flex justify-between items-center transition-all ${activeMemberIds.includes(member.id) ? 'bg-black text-white' : 'text-slate-600 hover:bg-slate-50'}`}
                        >
                          {member.name} {activeMemberIds.includes(member.id) && '✓'}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="relative" ref={notificationsRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="relative p-3 bg-white border border-black/5 rounded-full text-black hover:bg-slate-50 transition-all active:scale-95 shadow-sm"
              >
                <span>🔔</span>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-black text-white text-[8px] font-black w-5 h-5 rounded-full flex items-center justify-center animate-pulse border-2 border-white">
                    {unreadCount}
                  </span>
                )}
              </button>
              {showNotifications && (
                <div className="absolute right-0 mt-4 w-80 bg-white border border-black/10 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-[10px] font-black text-black uppercase tracking-widest">ACTIVITY LOG</h4>
                    <button onClick={clearNotifications} className="text-[9px] font-black text-slate-400 hover:text-black uppercase tracking-widest">Clear</button>
                  </div>
                  <div className="max-h-[32rem] overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-5 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-40' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[11px] font-black text-black uppercase tracking-tight">{n.title}</p>
                          <span className="text-[8px] font-black text-slate-400 uppercase">{n.timestamp}</span>
                        </div>
                        <p className="text-[11px] text-slate-500 leading-relaxed font-medium">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-16 text-center text-slate-400 italic text-[11px] font-medium tracking-wide">NO RECENT ALERTS</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="p-10 max-w-7xl mx-auto w-full flex-1">
          {children}
        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #000; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
      `}</style>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!formData.isShared) return;
    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const allAccounts = useMemo(() => [
    ...(state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId })),
    ...(state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId })),
    ...(state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId })),
    ...(state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }))
  ], [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Permanently delete this entry? Associated balances will be recalculated.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Please select a funding source."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    try {
      if (editingId) updateTransaction(transactionData);
      else addTransaction(transactionData);
      setShowModal(false);
    } catch (err) { alert("Failed to record transaction."); }
  };

  const updateContact = (index: number, field: 'name' | 'mobile', value: string) => {
    const newContacts = [...formData.contacts];
    newContacts[index] = { ...newContacts[index], [field]: value };
    setFormData(prev => ({ ...prev, contacts: newContacts }));
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const splitOptions: { id: SplitType; label: string; icon: string }[] = [
    { id: 'equal', label: 'Equally', icon: '⚖️' },
    { id: 'exact', label: 'Exact', icon: '🎯' },
    { id: 'percentage', label: 'Percent', icon: '📊' },
    { id: 'shares', label: 'Shares', icon: '🍕' },
    { id: 'adjustment', label: 'Adjust', icon: '➕' },
  ];

  const familyMembers = state.profile?.familyMembers || [];

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8">
        <div>
          <h3 className="text-sm font-black text-black uppercase tracking-[0.4em]">MASTER LEDGER</h3>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1 italic">FISCAL AUDIT TRAIL</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-6 py-3 bg-white text-black border border-black/10 rounded-none text-[10px] font-black uppercase tracking-widest hover:bg-black hover:text-white transition-all shadow-sm">INCOME</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-6 py-3 bg-white text-black border border-black/10 rounded-none text-[10px] font-black uppercase tracking-widest hover:bg-black hover:text-white transition-all shadow-sm">EXPENSE</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-6 py-3 bg-white text-black border border-black/10 rounded-none text-[10px] font-black uppercase tracking-widest hover:bg-black hover:text-white transition-all shadow-sm">ASSET</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-6 py-3 bg-black text-white rounded-none text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl shadow-black/10">LIABILITY</button>
        </div>
      </div>

      <div className="bg-white rounded-none border border-black/5 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-black text-[9px] font-black uppercase tracking-[0.3em] border-b border-black/5">
              <tr>
                <th className="px-8 py-6">DATE</th>
                <th className="px-8 py-6">DESCRIPTION</th>
                <th className="px-8 py-6">ENTITY</th>
                <th className="px-8 py-6">SOURCE</th>
                <th className="px-8 py-6 text-right">VALUE</th>
                <th className="px-8 py-6 text-center">ACCESS</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-8 py-5 text-[11px] font-black text-slate-400 whitespace-nowrap">{t.date}</td>
                    <td className="px-8 py-5">
                      <div className="flex items-center gap-3">
                        <p className="text-[12px] font-black text-black tracking-tight uppercase">{t.description}</p>
                        {t.isShared && <span className="bg-black text-white text-[8px] font-black px-2 py-0.5 uppercase tracking-widest">SHARED</span>}
                      </div>
                      <div className="flex flex-col">
                        {t.category && <span className="text-[9px] text-slate-400 font-black uppercase tracking-widest mt-0.5">{t.category}</span>}
                      </div>
                    </td>
                    <td className="px-8 py-5">
                      <span className="text-[9px] font-black text-black bg-slate-50 px-3 py-1 border border-black/5 uppercase tracking-widest">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-8 py-5">
                       <div className="flex items-center gap-3">
                         <span className="text-[11px] text-black font-black uppercase tracking-tight">{account?.name || 'MANUAL'}</span>
                         <span className="text-[8px] text-slate-400 font-black border border-slate-200 px-1.5 py-0.5 uppercase">{account?.type || 'REC'}</span>
                       </div>
                    </td>
                    <td className={`px-8 py-5 text-[12px] font-black text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-black' : 'text-slate-400'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-8 py-5 text-center">
                       <div className="flex items-center justify-center gap-4 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => handleEditClick(t)} className="text-[10px] font-black text-black hover:underline tracking-widest uppercase">EDIT</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="text-[10px] font-black text-rose-600 hover:underline tracking-widest uppercase">DEL</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-8 py-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <span className="text-6xl">🗄️</span>
                      <p className="text-[10px] font-black uppercase tracking-[0.4em] text-black">NO ENTRIES FOUND</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-black/80 backdrop-blur-md p-4 overflow-y-auto pt-10 pb-10">
          <div className="bg-white w-full max-w-xl rounded-none p-10 shadow-2xl animate-in zoom-in-95 duration-300 relative">
            <div className="flex justify-between items-center mb-10 border-b border-black/5 pb-6">
              <h3 className="text-sm font-black text-black uppercase tracking-[0.4em]">{editingId ? 'REVISE ENTRY' : `NEW ${formData.type.toUpperCase()}`}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-black font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">PRINCIPAL MEMBER</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px] uppercase tracking-widest transition-all" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                    <option value="">SELF</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name.toUpperCase()}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">CAPITAL SOURCE</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px] uppercase tracking-widest transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">SELECT SOURCE</option>
                    {allAccounts.filter(a => !formData.ownerId || a.ownerId === formData.ownerId || !a.ownerId).map(acc => (
                      <option key={acc.id} value={acc.id}>{acc.name.toUpperCase()}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">VALUATION ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-lg tracking-tight" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">EFFECTIVE DATE</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px]" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">MEMORANDUM</label>
                <input required placeholder="ENTRY DESCRIPTION" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px] uppercase tracking-widest transition-all" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-white text-black border border-black/10 font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-colors">ABORT</button>
                <button type="submit" className="flex-[2] px-4 py-4 bg-black text-white font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 shadow-xl shadow-black/20 transition-all">COMMIT ENTRY</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

