              <span className="absolute top-4 right-4 text-[8px] font-black uppercase text-black/30 bg-slate-50 px-2 py-0.5 border border-black/5">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-10">
                <div className="w-12 h-12 bg-black text-white flex items-center justify-center text-xl font-black">🏦</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">BALANCE</p>
                  <p className="text-2xl font-black text-black tracking-tighter">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="flex flex-col mb-1">
                 <h4 className="text-[13px] font-black text-black uppercase tracking-widest">{bank.name}</h4>
                 <span className="text-[9px] font-black uppercase text-slate-400 tracking-widest mt-1">
                    {bank.accountType === 'Others' ? bank.customAccountType?.toUpperCase() : bank.accountType?.toUpperCase()}
                 </span>
              </div>
              <p className="text-[11px] font-mono text-slate-400 mt-2">{bank.accountNumber || '**** **** ****'}</p>
              <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition-opacity pt-6 border-t border-slate-50 mt-6">
                <button onClick={() => handleEdit('bank', bank)} className="text-[9px] font-black uppercase text-black hover:underline tracking-widest">MODIFY</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[9px] font-black uppercase text-black hover:underline tracking-widest">LEDGER</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Credit Cards Section */}
      <section>
        <div className="flex justify-between items-end mb-10 border-b border-black/5 pb-6">
          <div className="flex flex-col">
            <h3 className="text-sm font-black text-black uppercase tracking-[0.4em]">CREDIT INSTRUMENTS</h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1 italic">UNSECURED DEBT OBLIGATIONS</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('card'); }}
            className="px-6 py-2 bg-black text-white rounded-none text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg shadow-black/10"
          >
            + ISSUE NEW
          </button>
