            const spendPercentage = annualLimit > 0 ? (annualUsed / annualLimit) * 100 : 0;

            return (
              <div key={card.id} className="relative overflow-hidden bg-black p-10 rounded-none text-white shadow-2xl group flex flex-col justify-between min-h-[320px]">
