                      </div>
                      <div className="flex justify-between items-center">
                        <p className="text-[9px] font-black text-white/30 uppercase tracking-widest">{formatCurrency(annualUsed, currency)} SPENT</p>
                        <p className="text-[9px] font-black text-white/30 uppercase tracking-widest">LIMIT {formatCurrency(annualLimit, currency)}</p>
                      </div>
                    </div>
                  )}
                </div>

                <div className="relative z-10 flex justify-between items-end border-t border-white/10 pt-8">
                  <p className="text-[13px] font-mono tracking-[0.3em] text-white/60">**** **** **** {card.last4}</p>
                  <div className="flex gap-6">
                    <button onClick={() => handleEdit('card', card)} className="text-[9px] font-black uppercase text-white/40 hover:text-white transition-colors tracking-widest">MODIFY</button>
                    <button onClick={() => setViewingHistory(card)} className="text-[9px] font-black uppercase text-white/40 hover:text-white transition-colors tracking-widest">LEDGER</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-lg rounded-none p-10 shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-sm font-black text-black uppercase tracking-[0.4em] mb-10 border-b border-black/5 pb-6">{editingAccount ? 'MODIFY' : 'INITIALIZE'} {showModal?.toUpperCase()}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}

      {viewingHistory && (
        <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { ...commonProps, lenderName: formData.name, balance: Number(formData.balance), last4: formData.last4, limit: formData.limit ? Number(formData.limit) : undefined, annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="space-y-2">
        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">PRINCIPAL OWNER</label>
        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px] uppercase tracking-widest" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">SELF (INDIVIDUAL)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name.toUpperCase()}</option>)}
        </select>
      </div>

      <div className="space-y-2">
        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">ENTITY NAME</label>
        <input required placeholder="E.G. CHASE, AMEX, LEDGER" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px] uppercase tracking-widest" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>

      <div className="space-y-2">
        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">CURRENT VALUATION</label>
        <input required type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-lg tracking-tight" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
      </div>

      <div className="flex gap-4 pt-6">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-4 bg-white text-black border border-black/10 font-black text-[10px] uppercase tracking-widest">DISCARD</button>
        <button type="submit" className="flex-[2] px-4 py-4 bg-black text-white font-black text-[10px] uppercase tracking-widest shadow-xl shadow-black/20">COMMIT ASSET</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4">
      <div className="bg-white w-full max-w-3xl rounded-none p-10 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-start mb-10 border-b border-black/5 pb-6">
          <div>
            <h3 className="text-sm font-black text-black uppercase tracking-[0.4em]">{account.name?.toUpperCase() || account.lenderName?.toUpperCase()} | LEDGER</h3>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1 italic">FISCAL AUDIT TRAIL</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-all font-black text-xl">✕</button>
        </div>

        <div className="bg-slate-50 p-8 rounded-none border border-black/5 mb-10 flex flex-wrap gap-10 items-end">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">PERIOD INCEPTION</label>
            <input type="date" className="p-4 bg-white border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px]" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-1">PERIOD CONCLUSION</label>
            <input type="date" className="p-4 bg-white border border-slate-200 rounded-none outline-none focus:ring-1 focus:ring-black font-black text-[11px]" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="flex-1 text-right">
             <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">NET VARIANCE</p>
             <p className={`text-2xl font-black tracking-tighter ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-black' : 'text-slate-400'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-4">
          {history.length > 0 ? (
            <div className="space-y-4">
              {history.map(t => (
                <div key={t.id} className="p-5 bg-white border border-black/5 rounded-none flex items-center justify-between hover:bg-slate-50 transition-all">
                   <div className="flex items-center gap-6">
                      <div className={`w-12 h-12 flex items-center justify-center text-sm font-black border ${t.type === 'Income' ? 'bg-black text-white border-black' : 'bg-white text-black border-black/10'}`}>
                        {t.type === 'Income' ? '↑' : '↓'}
                      </div>
                      <div>
                        <p className="text-[11px] font-black text-black uppercase tracking-widest">{t.description}</p>
                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{t.date} • {t.category || 'GENERAL'}</p>
                      </div>
                   </div>
                   <p className="text-[12px] font-black text-black">
                     {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                   </p>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-24 opacity-20 text-[11px] font-black tracking-widest uppercase italic">NO DATA IN PERIOD</div>
          )}
        </div>
      </div>
    </div>
  );
};

