import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time';

const Statements: React.FC = () => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();
    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    return txs;
  }, [filteredState.transactions, activePeriod]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;
  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  const isFamilyView = activeMemberIds.includes('all');
  const viewLabel = isFamilyView ? 'CONSOLIDATED GROUP' : 'INDIVIDUAL SCOPE';

  return (
    <div className="space-y-16 animate-in fade-in duration-700 pb-32">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-8 border-b border-black/5 pb-10">
        <div>
          <h2 className="text-4xl font-black text-black tracking-tighter uppercase">FISCAL AUDITS</h2>
          <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] mt-3">{viewLabel} • VERIFIED</p>
        </div>
        <div className="flex flex-wrap items-center gap-1 bg-slate-50 p-1 border border-black/5 rounded-full">
          {[
            { id: 'current_month', label: 'MONTH' },
            { id: 'last_90_days', label: 'QUARTER' },
            { id: 'ytd', label: 'YTD' },
            { id: 'all_time', label: 'MAX' }
          ].map(p => (
            <button
              key={p.id}
              onClick={() => setActivePeriod(p.id as Period)}
              className={`px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${
                activePeriod === p.id ? 'bg-black text-white shadow-xl' : 'text-slate-400 hover:text-black'
              }`}
            >
              {p.label}
            </button>
          ))}
        </div>
      </div>

      <section className="bg-white border border-black/10 overflow-hidden shadow-2xl shadow-black/5">
        <div className="bg-black px-12 py-10 text-white flex justify-between items-center">
          <div>
            <h3 className="text-xl font-black tracking-widest uppercase">INCOME STATEMENT</h3>
            <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em] mt-2">OPERATING PERFORMANCE REPORT</p>
          </div>
          <div className="text-right">
            <p className="text-[9px] font-black text-white/40 uppercase tracking-widest mb-2">NET MARGIN</p>
            <p className="text-4xl font-black tracking-tighter text-white">
              {formatCurrency(netSurplus, currency)}
            </p>
          </div>
        </div>

        <div className="p-12 grid grid-cols-1 md:grid-cols-2 gap-20">
          <div className="space-y-10">
            <div className="flex justify-between items-center border-b border-black/5 pb-4">
              <h4 className="text-[10px] font-black text-black uppercase tracking-[0.3em]">REVENUE</h4>
              <p className="text-xl font-black text-black">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="space-y-4">
              {filteredTransactions.filter(t => t.type === 'Income').map(t => (
                <div key={t.id} className="flex justify-between items-center py-4 border-b border-slate-50 group">
                  <div>
                    <p className="text-[11px] font-black text-black uppercase tracking-widest">{t.description}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter mt-1">{t.date}</p>
                  </div>
                  <p className="text-[12px] font-black text-black">+{formatCurrency(t.amount, currency)}</p>
                </div>
              ))}
