            </div>
            <div className="space-y-4">
              {filteredTransactions.filter(t => t.type === 'Expense').map(t => (
                <div key={t.id} className="flex justify-between items-center py-4 border-b border-slate-50 group">
                  <div>
                    <p className="text-[11px] font-black text-black uppercase tracking-widest">{t.description}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter mt-1">{t.category?.toUpperCase() || 'GENERAL'}</p>
                  </div>
