        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-black/5">
          <div className="p-12 space-y-12">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">ASSET RECOGNITION</h4>
            <div className="space-y-6">
              {[...filteredState.banks, ...filteredState.wallets, ...filteredState.assets].map((a: any) => (
                <div key={a.id} className="flex justify-between items-center border-b border-slate-50 pb-4">
                  <span className="text-[11px] font-black text-black uppercase tracking-widest">{a.name}</span>
                  <span className="text-[12px] font-black text-black">{formatCurrency(a.balance || a.value, currency)}</span>
                </div>
              ))}
            </div>
            <div className="pt-10 border-t-2 border-black flex justify-between items-center">
              <span className="text-xs font-black text-black uppercase tracking-[0.4em]">TOTAL ASSETS</span>
              <span className="text-2xl font-black text-black tracking-tighter">{formatCurrency(totalAssets, currency)}</span>
            </div>
