    e.preventDefault();
    if (mobileNumber.length >= 8) setAuthState('MFA');
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) setAuthState('PROFILE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateProfile({ ...formData, age: Number(formData.age), mobileNumber, isBoarded: true, familyMembers: [] });
    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });
    setAuthenticated(true);
  };

  if (authState === 'MOBILE') {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-10">
        <div className="w-full max-w-lg bg-white p-12 shadow-2xl animate-in zoom-in duration-500">
          <div className="mb-12 text-center">
            <h1 className="text-4xl font-black tracking-tighter mb-2">WEALTHFLOW</h1>
