                <input required type="tel" placeholder="MOBILE ACCESS KEY" className="w-full pl-6 bg-transparent outline-none font-black text-xl tracking-widest placeholder:text-slate-200" value={mobileNumber} onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))} />
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-black text-white font-black text-[11px] uppercase tracking-[0.4em] hover:bg-slate-800 transition-all shadow-2xl shadow-black/30">INITIATE SESSION</button>
          </form>
        </div>
      </div>
    );
