  if (authState === 'MFA') {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-10">
        <div className="w-full max-w-lg bg-white p-12 shadow-2xl animate-in fade-in slide-in-from-right-10 duration-500">
          <h2 className="text-sm font-black text-black uppercase tracking-[0.4em] mb-4">SECURITY VERIFICATION</h2>
          <p className="text-[11px] text-slate-500 font-medium tracking-wide leading-relaxed mb-12">WE HAVE TRANSMITTED A VERIFICATION TOKEN TO <span className="text-black font-black">+{mobileNumber}</span></p>
          <div className="flex justify-between gap-4 mb-12">
            {otp.map((digit, i) => (
              <input key={i} id={`otp-${i}`} required type="number" className="w-full h-20 text-center text-4xl font-black bg-slate-50 border border-slate-100 focus:border-black focus:bg-white outline-none transition-all" value={digit} onChange={e => {
                const n = [...otp]; n[i] = e.target.value.slice(-1); setOtp(n);
                if (e.target.value && i < 3) document.getElementById(`otp-${i+1}`)?.focus();
