import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const memberSelectorRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);

  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (memberSelectorRef.current && !memberSelectorRef.current.contains(event.target as Node)) {
        setShowMemberSelector(false);
      }
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const toggleMember = (id: string) => {
    let current = activeMemberIds.includes('all') ? [] : [...activeMemberIds];
    if (current.includes(id)) {
      current = current.filter(i => i !== id);
    } else {
      current.push(id);
    }
    setActiveMemberIds(current);
  };

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'DASHBOARD', icon: '✦' },
    { id: 'transactions', label: 'LEDGER', icon: '◰' },
    { id: 'accounts', label: 'WEALTH', icon: '▣' },
    { id: 'statements', label: 'REPORTS', icon: '▤' },
    { id: 'profile', label: 'ACCOUNT', icon: '◎' },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#050505] text-white selection:bg-[#33F8FF] selection:text-black">
      {/* Sleek Deep Dark Sidebar */}
      <aside className="w-full md:w-64 bg-[#0A0A0C] border-r border-white/5 z-30 flex flex-col">
        <div className="p-8">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-gradient-to-tr from-[#33F8FF] to-[#D4AF37] rounded-lg"></div>
             <h1 className="text-lg font-black tracking-tighter">WealthFlow</h1>
          </div>
          <p className="text-[9px] font-bold text-white/20 tracking-[0.4em] mt-2">PREMIUM OS</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl text-[10px] font-black tracking-widest transition-all group ${
                activeTab === item.id 
                  ? 'bg-white/5 text-white ring-1 ring-white/10' 
                  : 'text-white/30 hover:text-white/60'
              }`}
            >
              <span className={`text-sm ${activeTab === item.id ? 'text-[#33F8FF]' : 'text-white/10 group-hover:text-white/30'}`}>{item.icon}</span>
              {item.label}
              {activeTab === item.id && <div className="ml-auto w-1 h-1 rounded-full bg-[#33F8FF] shadow-[0_0_8px_#33F8FF]"></div>}
            </button>
          ))}

          <div className="pt-10">
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-4 rounded-xl text-[9px] font-black tracking-widest text-white/10 hover:text-rose-500 transition-colors uppercase"
            >
              <span>⎗</span> Factory Reset
            </button>
          </div>
        </nav>

        <div className="p-6">
           <div className="p-5 bg-gradient-to-br from-white/[0.03] to-transparent border border-white/5 rounded-2xl">
             <p className="text-[8px] font-black text-white/20 uppercase tracking-widest mb-1">MEMBERSHIP</p>
             <p className="text-[11px] font-bold text-[#D4AF37] tracking-tight">BLACK TIER</p>
           </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative flex flex-col custom-scrollbar">
        {/* Transparent Header */}
        <header className="sticky top-0 bg-[#050505]/60 backdrop-blur-2xl border-b border-white/5 px-8 py-5 z-40 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-6">
            <h2 className="text-[11px] font-black text-white/40 uppercase tracking-[0.3em]">
              {navItems.find(i => i.id === activeTab)?.label || activeTab}
            </h2>
            <button 
              onClick={handleSync}
              disabled={isSyncing}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-[9px] font-black uppercase tracking-[0.2em] transition-all border ${
                isSyncing 
                  ? 'bg-white/5 text-white/20 border-white/10' 
                  : 'bg-white text-black hover:bg-white/90 active:scale-95 border-white shadow-[0_0_20px_rgba(255,255,255,0.1)]'
              }`}
            >
              {isSyncing ? 'UPDATING' : 'SYNC CLOUD'}
            </button>
          </div>

          <div className="flex items-center gap-5">
            <div className="flex items-center gap-1 bg-white/5 p-1 border border-white/5 rounded-full">
              <button 
                onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }}
                className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${currentView === 'me' ? 'bg-white text-black' : 'text-white/20 hover:text-white/40'}`}
              > INDIVIDUAL </button>
              <button 
                onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }}
                className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${currentView === 'family' ? 'bg-white text-black' : 'text-white/20 hover:text-white/40'}`}
              > CONSOLIDATED </button>
            </div>

            <div className="relative" ref={notificationsRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="relative p-3 bg-white/5 border border-white/5 rounded-xl text-white/60 hover:text-white transition-all active:scale-95"
              >
                <span className="text-lg">◈</span>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-[#33F8FF] text-black text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-[#050505]">
                    {unreadCount}
                  </span>
                )}
              </button>
              {showNotifications && (
                <div className="absolute right-0 mt-4 w-80 glass-panel border border-white/10 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-5 border-b border-white/5 flex justify-between items-center bg-white/[0.02]">
                    <h4 className="text-[9px] font-black text-white/40 uppercase tracking-widest">ALERT CENTER</h4>
                    <button onClick={clearNotifications} className="text-[8px] font-black text-[#33F8FF] uppercase tracking-widest">Mark All</button>
                  </div>
                  <div className="max-h-[32rem] overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-5 border-b border-white/5 transition-colors cursor-pointer hover:bg-white/[0.03] ${n.isRead ? 'opacity-30' : 'bg-white/[0.01]'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[10px] font-black text-white uppercase tracking-tight">{n.title}</p>
                          <span className="text-[7px] font-black text-white/20 uppercase">{n.timestamp}</span>
                        </div>
                        <p className="text-[10px] text-white/40 leading-relaxed font-medium">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-16 text-center text-white/10 italic text-[10px] font-black tracking-widest">NO NEW ALERTS</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="p-8 md:p-12 max-w-7xl mx-auto w-full flex-1">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard } from '../types';

const Accounts: React.FC = () => {
  const { filteredState, state } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'CLIENT';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name.toUpperCase() : 'UNKNOWN';
  };

  const calculateAnnualSpend = (cardId: string) => {
    const currentYear = new Date().getFullYear();
    return (filteredState.transactions || [])
      .filter(t => t.accountId === cardId && t.type === 'Expense' && new Date(t.date).getFullYear() === currentYear)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  return (
    <div className="space-y-16 animate-in fade-in duration-1000">
      {/* Depository Section */}
      <section>
        <div className="flex justify-between items-end mb-10 border-b border-white/5 pb-8">
          <div className="flex flex-col">
            <h3 className="text-[12px] font-black text-white/40 uppercase tracking-[0.5em]">DEPOSITORY INSTRUMENTS</h3>
            <p className="text-[9px] text-[#33F8FF] font-black uppercase tracking-widest mt-2">LIQUIDITY POOLS</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('bank'); }}
