        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-[#121214] p-8 rounded-3xl border border-white/5 relative group hover:border-[#33F8FF]/30 transition-all shadow-2xl">
              <span className="absolute top-4 right-6 text-[8px] font-black uppercase text-white/20 bg-white/5 px-2 py-1 rounded-lg border border-white/5">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-10">
                <div className="w-12 h-12 bg-white/5 border border-white/10 text-[#33F8FF] rounded-2xl flex items-center justify-center text-xl font-black shadow-inner">🏦</div>
                <div className="text-right">
                  <p className="text-[8px] text-white/20 font-black uppercase tracking-widest mb-1">AVAILABLE</p>
                  <p className="text-2xl font-black text-white tracking-tighter">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="flex flex-col mb-1">
                 <h4 className="text-[14px] font-black text-white uppercase tracking-tight">{bank.name}</h4>
                 <span className="text-[9px] font-black uppercase text-[#33F8FF] tracking-widest mt-1">
                    {bank.accountType === 'Others' ? bank.customAccountType?.toUpperCase() : bank.accountType?.toUpperCase()}
                 </span>
              </div>
              <p className="text-[11px] font-mono text-white/10 mt-3 tracking-widest">{bank.accountNumber || '•••• •••• ••••'}</p>
              <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition-all pt-6 border-t border-white/5 mt-6 translate-y-2 group-hover:translate-y-0">
                <button onClick={() => handleEdit('bank', bank)} className="text-[9px] font-black uppercase text-[#33F8FF] hover:underline tracking-widest">Adjust</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[9px] font-black uppercase text-white/40 hover:text-white transition-colors tracking-widest">Analytics</button>
