                  {annualLimit > 0 && (
                    <div className="mb-10 space-y-4 bg-white/[0.02] p-6 rounded-2xl border border-white/5">
                      <div className="flex justify-between items-center">
                        <p className="text-[8px] font-black uppercase tracking-[0.4em] text-white/20">YEARLY UTILIZATION</p>
                        <p className={`text-[10px] font-black ${spendPercentage > 85 ? 'text-rose-400' : 'text-[#33F8FF]'}`}>{Math.round(spendPercentage)}%</p>
                      </div>
                      <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${spendPercentage > 85 ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.4)]' : 'bg-[#33F8FF] shadow-[0_0_10px_rgba(51,248,255,0.4)]'}`} 
                          style={{ width: `${Math.min(100, spendPercentage)}%` }} 
