const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { ...commonProps, lenderName: formData.name, balance: Number(formData.balance), last4: formData.last4, limit: formData.limit ? Number(formData.limit) : undefined, annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      <div className="space-y-3">
        <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">PRINCIPAL OWNER</label>
        <select className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="" className="bg-[#121214]">CLIENT (PRIMARY)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id} className="bg-[#121214]">{m.name.toUpperCase()}</option>)}
        </select>
      </div>

      <div className="space-y-3">
        <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">IDENTIFIER NAME</label>
        <input required placeholder="E.G. CHASE SAPPHIRE, GOLDMAN SACHS" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all placeholder:text-white/10" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>

      <div className="space-y-3">
        <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">VALUATION</label>
        <input required type="number" placeholder="0.00" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-2xl tracking-tighter text-white transition-all" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
      </div>

      <div className="flex gap-5 pt-10">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-4 bg-white/5 text-white/40 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-white/10 transition-colors">Discard</button>
        <button type="submit" className="flex-[2] px-4 py-4 bg-white text-black rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-white/10 hover:scale-[1.02] transition-all">Finalize Asset</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-xl p-4">
      <div className="bg-[#0F0F11] w-full max-w-4xl rounded-[3rem] p-12 shadow-2xl animate-in fade-in slide-in-from-bottom-12 duration-500 max-h-[90vh] flex flex-col border border-white/10">
        <div className="flex justify-between items-start mb-12 border-b border-white/5 pb-8">
          <div>
            <h3 className="text-[14px] font-black text-white uppercase tracking-[0.4em]">{account.name?.toUpperCase() || account.lenderName?.toUpperCase()} | ANALYTICS</h3>
            <p className="text-[10px] font-bold text-[#33F8FF] uppercase tracking-widest mt-2">DEEP LEDGER INSPECTION</p>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 text-white/20 hover:text-white rounded-full transition-all font-black text-xl">✕</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">
          <div className="bg-white/5 p-6 rounded-2xl border border-white/5">
             <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block mb-2">PERIOD START</label>
             <input type="date" className="w-full bg-transparent border-none outline-none font-black text-xs text-white" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div className="bg-white/5 p-6 rounded-2xl border border-white/5">
             <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block mb-2">PERIOD END</label>
             <input type="date" className="w-full bg-transparent border-none outline-none font-black text-xs text-white" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="bg-[#121214] p-6 rounded-2xl border border-white/5 text-right flex flex-col justify-center">
             <p className="text-[9px] font-black text-white/20 uppercase tracking-widest mb-1">NET VARIANCE</p>
             <p className={`text-2xl font-black tracking-tighter ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-[#33F8FF]' : 'text-rose-400'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-4 space-y-4">
          {history.length > 0 ? (
            history.map(t => (
              <div key={t.id} className="p-6 bg-white/[0.02] border border-white/5 rounded-2xl flex items-center justify-between hover:bg-white/[0.04] transition-all group">
                 <div className="flex items-center gap-6">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xs font-black border transition-all ${t.type === 'Income' ? 'bg-[#33F8FF]/10 text-[#33F8FF] border-[#33F8FF]/20' : 'bg-rose-500/10 text-rose-400 border-rose-500/20'}`}>
                      {t.type === 'Income' ? 'CR' : 'DR'}
                    </div>
                    <div>
                      <p className="text-[12px] font-black text-white uppercase tracking-widest">{t.description}</p>
                      <p className="text-[9px] font-black text-white/10 uppercase tracking-widest mt-1">{t.date} • {t.category || 'GENERAL'}</p>
                    </div>
                 </div>
                 <div className="text-right">
                    <p className={`text-[13px] font-black ${t.type === 'Income' ? 'text-[#33F8FF]' : 'text-white/40'}`}>
                      {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                    </p>
                 </div>
              </div>
            ))
          ) : (
            <div className="text-center py-32 opacity-10 text-[11px] font-black tracking-[0.5em] uppercase italic">NO DATA IN SCOPE</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Accounts;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!formData.isShared) return;
    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const allAccounts = useMemo(() => [
    ...(state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId })),
    ...(state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId })),
    ...(state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId })),
    ...(state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }))
  ], [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Authorize permanent ledger deletion?")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source account required."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Self';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Self';
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-1000">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8">
        <div>
          <h3 className="text-[12px] font-black text-white/40 uppercase tracking-[0.5em]">MASTER LEDGER</h3>
          <p className="text-[10px] text-[#33F8FF] font-black uppercase tracking-widest mt-2">REAL-TIME FLOW</p>
        </div>
        <div className="flex flex-wrap items-center gap-4">
          <button onClick={() => handleOpenModal('Income')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-[#33F8FF] hover:border-[#33F8FF]/30 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-rose-400 hover:border-rose-400/30 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-[#D4AF37] hover:border-[#D4AF37]/30 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-6 py-3 bg-white text-black rounded-xl text-[10px] font-black uppercase tracking-widest hover:scale-105 active:scale-95 transition-all shadow-2xl shadow-white/10">Liability</button>
        </div>
      </div>

      <div className="glass-panel rounded-[2rem] border border-white/5 shadow-2xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-white/[0.02] text-white/20 text-[9px] font-black uppercase tracking-[0.4em] border-b border-white/5">
              <tr>
                <th className="px-8 py-8">TIMESTAMP</th>
                <th className="px-8 py-8">DESCRIPTION</th>
                <th className="px-8 py-8">ENTITY</th>
                <th className="px-8 py-8">SOURCE</th>
                <th className="px-8 py-8 text-right">VALUATION</th>
                <th className="px-8 py-8 text-center">TOOLS</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/[0.03]">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-white/[0.02] transition-colors group">
                    <td className="px-8 py-6 text-[11px] font-black text-white/20 whitespace-nowrap">{t.date}</td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                        <p className="text-[13px] font-black text-white tracking-tight uppercase">{t.description}</p>
                        {t.isShared && <span className="bg-[#33F8FF]/10 text-[#33F8FF] text-[8px] font-black px-2 py-0.5 rounded-md uppercase tracking-widest">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-1">
                        {t.category && <span className="text-[9px] text-white/20 font-black uppercase tracking-widest">{t.category}</span>}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[9px] font-black text-white/40 bg-white/5 px-3 py-1.5 rounded-lg border border-white/5 uppercase tracking-widest">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-8 py-6">
                       <div className="flex items-center gap-3">
                         <span className="text-[11px] text-white font-black uppercase tracking-tight">{account?.name || 'MANUAL'}</span>
                       </div>
                    </td>
                    <td className={`px-8 py-6 text-[13px] font-black text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-[#33F8FF]' : 'text-white/40'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-4 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-white/20 hover:text-white transition-colors">✎</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-white/20 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-8 py-40 text-center">
                    <div className="flex flex-col items-center gap-6 opacity-10">
                      <span className="text-6xl">◇</span>
                      <p className="text-[11px] font-black uppercase tracking-[0.5em] text-white">EMPTY LEDGER</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-black/95 backdrop-blur-xl p-4 overflow-y-auto pt-20">
          <div className="bg-[#121214] w-full max-w-xl rounded-[2.5rem] p-12 border border-white/10 shadow-2xl animate-in zoom-in-95 duration-300 relative">
            <div className="flex justify-between items-center mb-12 border-b border-white/5 pb-8">
              <h3 className="text-[12px] font-black text-white/40 uppercase tracking-[0.5em]">RECORD {formData.type.toUpperCase()}</h3>
              <button onClick={() => setShowModal(false)} className="text-white/20 hover:text-white font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">CLIENT ASSIGNMENT</label>
                  <select className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                    <option value="" className="bg-[#121214]">PRIMARY CLIENT</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id} className="bg-[#121214]">{m.name.toUpperCase()}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">FUNDING INSTRUMENT</label>
                  <select required className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="" className="bg-[#121214]">SELECT SOURCE</option>
                    {allAccounts.filter(a => !formData.ownerId || a.ownerId === formData.ownerId || !a.ownerId).map(acc => (
                      <option key={acc.id} value={acc.id} className="bg-[#121214]">{acc.name.toUpperCase()}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">AMOUNT ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-2xl tracking-tighter text-white transition-all" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">LEDGER DATE</label>
                  <input required type="date" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] text-white" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">DESCRIPTION</label>
                <input required placeholder="E.G. QUARTERLY DIVIDEND, UTILITY BILL" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all placeholder:text-white/10" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-5 pt-10">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-white/5 text-white/40 font-black text-[10px] uppercase tracking-widest rounded-2xl hover:bg-white/10">Abort</button>
                <button type="submit" className="flex-[2] px-4 py-4 bg-white text-black font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-2xl shadow-white/10 hover:scale-[1.02] transition-all">Authorize Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

