    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Authorize permanent ledger deletion?")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source account required."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Self';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Self';
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-1000">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8">
        <div>
          <h3 className="text-[12px] font-black text-white/40 uppercase tracking-[0.5em]">MASTER LEDGER</h3>
          <p className="text-[10px] text-[#33F8FF] font-black uppercase tracking-widest mt-2">REAL-TIME FLOW</p>
        </div>
        <div className="flex flex-wrap items-center gap-4">
          <button onClick={() => handleOpenModal('Income')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-[#33F8FF] hover:border-[#33F8FF]/30 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-rose-400 hover:border-rose-400/30 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-6 py-3 bg-white/5 text-white/60 border border-white/5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:text-[#D4AF37] hover:border-[#D4AF37]/30 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-6 py-3 bg-white text-black rounded-xl text-[10px] font-black uppercase tracking-widest hover:scale-105 active:scale-95 transition-all shadow-2xl shadow-white/10">Liability</button>
        </div>
      </div>

      <div className="glass-panel rounded-[2rem] border border-white/5 shadow-2xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-white/[0.02] text-white/20 text-[9px] font-black uppercase tracking-[0.4em] border-b border-white/5">
              <tr>
                <th className="px-8 py-8">TIMESTAMP</th>
                <th className="px-8 py-8">DESCRIPTION</th>
                <th className="px-8 py-8">ENTITY</th>
                <th className="px-8 py-8">SOURCE</th>
                <th className="px-8 py-8 text-right">VALUATION</th>
                <th className="px-8 py-8 text-center">TOOLS</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/[0.03]">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-white/[0.02] transition-colors group">
                    <td className="px-8 py-6 text-[11px] font-black text-white/20 whitespace-nowrap">{t.date}</td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                        <p className="text-[13px] font-black text-white tracking-tight uppercase">{t.description}</p>
                        {t.isShared && <span className="bg-[#33F8FF]/10 text-[#33F8FF] text-[8px] font-black px-2 py-0.5 rounded-md uppercase tracking-widest">Shared</span>}
                      </div>
                      <div className="flex flex-col mt-1">
                        {t.category && <span className="text-[9px] text-white/20 font-black uppercase tracking-widest">{t.category}</span>}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[9px] font-black text-white/40 bg-white/5 px-3 py-1.5 rounded-lg border border-white/5 uppercase tracking-widest">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-8 py-6">
                       <div className="flex items-center gap-3">
                         <span className="text-[11px] text-white font-black uppercase tracking-tight">{account?.name || 'MANUAL'}</span>
                       </div>
                    </td>
                    <td className={`px-8 py-6 text-[13px] font-black text-right ${t.type === 'Income' || t.type === 'Liability' ? 'text-[#33F8FF]' : 'text-white/40'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-4 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-white/20 hover:text-white transition-colors">✎</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-white/20 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-8 py-40 text-center">
                    <div className="flex flex-col items-center gap-6 opacity-10">
                      <span className="text-6xl">◇</span>
                      <p className="text-[11px] font-black uppercase tracking-[0.5em] text-white">EMPTY LEDGER</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-black/95 backdrop-blur-xl p-4 overflow-y-auto pt-20">
          <div className="bg-[#121214] w-full max-w-xl rounded-[2.5rem] p-12 border border-white/10 shadow-2xl animate-in zoom-in-95 duration-300 relative">
            <div className="flex justify-between items-center mb-12 border-b border-white/5 pb-8">
              <h3 className="text-[12px] font-black text-white/40 uppercase tracking-[0.5em]">RECORD {formData.type.toUpperCase()}</h3>
              <button onClick={() => setShowModal(false)} className="text-white/20 hover:text-white font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">CLIENT ASSIGNMENT</label>
                  <select className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                    <option value="" className="bg-[#121214]">PRIMARY CLIENT</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id} className="bg-[#121214]">{m.name.toUpperCase()}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">FUNDING INSTRUMENT</label>
                  <select required className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="" className="bg-[#121214]">SELECT SOURCE</option>
                    {allAccounts.filter(a => !formData.ownerId || a.ownerId === formData.ownerId || !a.ownerId).map(acc => (
                      <option key={acc.id} value={acc.id} className="bg-[#121214]">{acc.name.toUpperCase()}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">AMOUNT ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-2xl tracking-tighter text-white transition-all" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-3">
                  <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">LEDGER DATE</label>
                  <input required type="date" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] text-white" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-[9px] font-black text-white/20 uppercase tracking-widest block ml-1">DESCRIPTION</label>
                <input required placeholder="E.G. QUARTERLY DIVIDEND, UTILITY BILL" className="w-full p-4 bg-white/5 border border-white/5 rounded-2xl outline-none focus:ring-1 focus:ring-[#33F8FF] font-black text-[11px] uppercase tracking-widest text-white transition-all placeholder:text-white/10" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-5 pt-10">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-white/5 text-white/40 font-black text-[10px] uppercase tracking-widest rounded-2xl hover:bg-white/10">Abort</button>
                <button type="submit" className="flex-[2] px-4 py-4 bg-white text-black font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-2xl shadow-white/10 hover:scale-[1.02] transition-all">Authorize Entry</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

