          })}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-md rounded-2xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-lg font-bold text-slate-800 mb-8 pb-4 border-b border-slate-100">Configure {showModal?.charAt(0).toUpperCase() + showModal?.slice(1)}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}

      {viewingHistory && (
        <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { ...commonProps, lenderName: formData.name, balance: Number(formData.balance), last4: formData.last4, limit: formData.limit ? Number(formData.limit) : undefined, annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Owner</label>
        <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">Self (Individual)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
        </select>
      </div>

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Entity Name</label>
        <input required placeholder="e.g. Chase, Amex, Ledger" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>

      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Valuation</label>
        <input required type="number" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-xl" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
      </div>

      <div className="flex gap-4 pt-6">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-xs">Discard</button>
        <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-indigo-100">Save Asset</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-3xl rounded-2xl p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-start mb-8 border-b border-slate-100 pb-4">
          <div>
            <h3 className="text-lg font-bold text-slate-800">{account.name || account.lenderName} Ledger</h3>
            <p className="text-xs font-medium text-indigo-500 uppercase tracking-widest mt-1">Audit Trail</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-300 hover:text-slate-600 transition-all text-xl">✕</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8 bg-slate-50 p-6 rounded-2xl border border-slate-100">
          <div>
             <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1 ml-1">From</label>
             <input type="date" className="w-full bg-white border border-slate-200 rounded-xl p-2.5 text-xs font-bold" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div>
             <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1 ml-1">To</label>
             <input type="date" className="w-full bg-white border border-slate-200 rounded-xl p-2.5 text-xs font-bold" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="text-right flex flex-col justify-center">
             <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Net Flow</p>
             <p className={`text-xl font-black ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-3">
          {history.length > 0 ? (
            history.map(t => (
              <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-xl flex items-center justify-between hover:border-indigo-100 transition-all">
                 <div className="flex items-center gap-4">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-sm font-bold shadow-sm ${t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                      {t.type === 'Income' ? '↑' : '↓'}
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-800">{t.description}</p>
                      <p className="text-[10px] font-medium text-slate-400">{t.date} • {t.category || 'General'}</p>
                    </div>
                 </div>
                 <p className={`text-sm font-black ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                   {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                 </p>
              </div>
            ))
          ) : (
            <div className="text-center py-20 opacity-30 text-slate-400 text-sm italic">No entries in range</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Accounts;

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!formData.isShared) return;
    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const allAccounts = useMemo(() => [
    ...(state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId })),
    ...(state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId })),
    ...(state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId })),
    ...(state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }))
  ], [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (id: string) => {
    if (window.confirm("Delete this entry forever? Balance effects will be reversed.")) {
      deleteTransaction(id);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source required."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-lg font-bold text-slate-800 tracking-tight">Financial Ledger</h3>
          <p className="text-xs text-slate-400 font-medium">Record and track all cash movements</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-5 py-2.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-xs font-bold hover:bg-emerald-100 transition-all shadow-sm">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-5 py-2.5 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all shadow-sm">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-5 py-2.5 bg-white text-indigo-600 border border-indigo-100 rounded-xl text-xs font-bold hover:bg-indigo-50 transition-all shadow-sm">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Description</th>
                <th className="px-6 py-5">Owner</th>
                <th className="px-6 py-5">Source</th>
                <th className="px-6 py-5 text-right">Amount</th>
                <th className="px-6 py-5 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-medium text-slate-400 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800 tracking-tight">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-50 text-indigo-600 text-[9px] font-bold px-2 py-0.5 rounded-md uppercase">Shared</span>}
                      </div>
                      {t.category && <span className="text-[10px] text-slate-400 font-bold uppercase mt-1 inline-block">{t.category}</span>}
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded-md uppercase">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <span className="text-xs text-slate-700 font-medium">{account?.name || 'Manual'}</span>
                    </td>
                    <td className={`px-6 py-4 text-sm font-black text-right ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✎</button>
                         <button onClick={() => handleDeleteClick(t.id)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-6 py-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <span className="text-5xl">📋</span>
                      <p className="text-sm font-bold uppercase tracking-widest text-slate-800">No Transactions Found</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 overflow-y-auto pt-16">
