import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time';

const Statements: React.FC = () => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();
    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    return txs;
  }, [filteredState.transactions, activePeriod]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;
  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  const isFamilyView = activeMemberIds.includes('all');
  const viewLabel = isFamilyView ? 'Consolidated Family View' : 'Individual Portfolio';

  return (
    <div className="space-y-12 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 border-b border-slate-200 pb-8">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Financial Reports</h2>
          <p className="text-sm font-medium text-slate-400 mt-2">{viewLabel}</p>
        </div>
        <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm">
          {[
            { id: 'current_month', label: 'Month' },
            { id: 'last_90_days', label: 'Quarter' },
            { id: 'ytd', label: 'YTD' },
            { id: 'all_time', label: 'All Time' }
          ].map(p => (
            <button
              key={p.id}
              onClick={() => setActivePeriod(p.id as Period)}
              className={`px-6 py-1.5 rounded-full text-xs font-bold transition-all ${
                activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md shadow-indigo-100' : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              {p.label}
            </button>
          ))}
        </div>
      </div>

      <section className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-10 py-8 text-white flex justify-between items-center">
          <div>
            <h3 className="text-lg font-bold tracking-tight">Income Statement</h3>
            <p className="text-slate-400 text-xs mt-1 uppercase tracking-widest font-medium">Operations Report</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Net Savings</p>
            <p className={`text-3xl font-black tracking-tight ${netSurplus >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
              {formatCurrency(netSurplus, currency)}
            </p>
          </div>
        </div>

        <div className="p-10 grid grid-cols-1 md:grid-cols-2 gap-16">
          <div className="space-y-8">
            <div className="flex justify-between items-center border-b border-slate-100 pb-3">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Revenue</h4>
              <p className="text-lg font-black text-emerald-600">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="space-y-4">
              {filteredTransactions.filter(t => t.type === 'Income').length > 0 ? filteredTransactions.filter(t => t.type === 'Income').map(t => (
                <div key={t.id} className="flex justify-between items-center py-3 border-b border-slate-50 group">
                  <div>
                    <p className="text-sm font-bold text-slate-800">{t.description}</p>
                    <p className="text-[10px] font-medium text-slate-400 mt-0.5">{t.date}</p>
                  </div>
                  <p className="text-sm font-bold text-emerald-600">+{formatCurrency(t.amount, currency)}</p>
                </div>
              )) : <p className="py-10 text-center text-slate-300 italic text-xs">No income recorded</p>}
            </div>
          </div>

          <div className="space-y-8">
            <div className="flex justify-between items-center border-b border-slate-100 pb-3">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Expenses</h4>
              <p className="text-lg font-black text-rose-500">{formatCurrency(periodExpense, currency)}</p>
            </div>
            <div className="space-y-4">
              {filteredTransactions.filter(t => t.type === 'Expense').length > 0 ? filteredTransactions.filter(t => t.type === 'Expense').map(t => (
                <div key={t.id} className="flex justify-between items-center py-3 border-b border-slate-50 group">
                  <div>
                    <p className="text-sm font-bold text-slate-800">{t.description}</p>
                    <p className="text-[10px] font-medium text-slate-400 mt-0.5">{t.category?.toUpperCase() || 'GENERAL'}</p>
                  </div>
                  <p className="text-sm font-bold text-slate-600">-{formatCurrency(t.amount, currency)}</p>
                </div>
              )) : <p className="py-10 text-center text-slate-300 italic text-xs">No expenses recorded</p>}
