            <p className="text-slate-400 text-xs mt-1 uppercase tracking-widest font-medium">Wealth Position</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Net Liquidity</p>
            <p className="text-3xl font-black tracking-tight text-indigo-600">
              {formatCurrency(netWorth, currency)}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          <div className="p-10 space-y-8">
            <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Assets</h4>
            <div className="space-y-5">
              {[...filteredState.banks, ...filteredState.wallets, ...filteredState.assets].map((a: any) => (
                <div key={a.id} className="flex justify-between items-center border-b border-slate-50 pb-3">
                  <span className="text-sm font-bold text-slate-700">{a.name}</span>
                  <span className="text-sm font-black text-slate-800">{formatCurrency(a.balance || a.value, currency)}</span>
                </div>
              ))}
            </div>
            <div className="pt-8 border-t border-slate-200 flex justify-between items-center">
              <span className="text-xs font-black text-slate-800 uppercase tracking-widest">Gross Assets</span>
              <span className="text-2xl font-black text-indigo-600 tracking-tight">{formatCurrency(totalAssets, currency)}</span>
            </div>
          </div>

          <div className="p-10 space-y-8 bg-slate-50/30">
            <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Total Liabilities</h4>
            <div className="space-y-5">
              {[...filteredState.cards, ...filteredState.liabilities].map((l: any) => (
