import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';

const countries = [
  { name: 'India', currency: 'INR' }, { name: 'United Kingdom', currency: 'GBP' }, { name: 'United States', currency: 'USD' },
  { name: 'Singapore', currency: 'SGD' }, { name: 'United Arab Emirates', currency: 'AED' }, { name: 'Japan', currency: 'JPY' }
];

const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PROFILE' | 'CLOUD'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [isVerifyingCloud, setIsVerifyingCloud] = useState(false);

  const [formData, setFormData] = useState({
    name: state.profile.name || '',
    designation: state.profile.designation || '',
    age: state.profile.age ? String(state.profile.age) : '',
    city: state.profile.city || '',
    country: state.profile.country || 'United States',
    currency: state.profile.currency || 'USD',
    openingCash: '0',
    cloudDatabaseLink: '',
    cloudDatabaseName: 'MyWealthDB_2024'
  });

  const handleSendOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) setAuthState('MFA');
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) setAuthState('PROFILE');
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthState('CLOUD');
  };

  const handleCloudSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsVerifyingCloud(true);

    // Simulate connection to Google Drive and file creation
    await new Promise(resolve => setTimeout(resolve, 2000));

    updateProfile({ 
      ...formData, 
      age: Number(formData.age), 
      mobileNumber, 
      isBoarded: true, 
      familyMembers: [],
      cloudDatabaseLink: formData.cloudDatabaseLink,
      cloudDatabaseName: formData.cloudDatabaseName
    });

    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });
    setAuthenticated(true);
  };

  if (authState === 'MOBILE') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-xl animate-in zoom-in duration-500 border border-slate-100">
          <div className="mb-10 text-center">
            <div className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center text-2xl font-black mx-auto mb-4">M</div>
            <h1 className="text-3xl font-black tracking-tight text-slate-800">MyFin</h1>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-2">Private Wealth Portal</p>
          </div>
          <form onSubmit={handleSendOtp} className="space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Authentication Key</label>
              <div className="relative border-b-2 border-slate-200 pb-3 focus-within:border-indigo-600 transition-colors">
                <span className="absolute left-0 text-slate-400 font-bold">+</span>
                <input required type="tel" placeholder="Mobile Access Code" className="w-full pl-6 bg-transparent outline-none font-bold text-xl tracking-widest placeholder:text-slate-200" value={mobileNumber} onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))} />
              </div>
            </div>
            <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-bold text-sm uppercase rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">Request Access</button>
          </form>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-xl animate-in fade-in slide-in-from-right-10 duration-500 border border-slate-100">
          <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-3">Security Check</h2>
          <p className="text-xs text-slate-500 font-medium leading-relaxed mb-10">Verification code sent to <span className="text-slate-800 font-bold">+{mobileNumber}</span></p>
          <div className="flex justify-between gap-3 mb-10">
            {otp.map((digit, i) => (
              <input key={i} id={`otp-${i}`} required type="number" className="w-full h-16 text-center text-3xl font-black bg-slate-50 border border-slate-200 rounded-2xl focus:border-indigo-600 focus:bg-white outline-none transition-all" value={digit} onChange={e => {
                const n = [...otp]; n[i] = e.target.value.slice(-1); setOtp(n);
                if (e.target.value && i < 3) document.getElementById(`otp-${i+1}`)?.focus();
              }} />
            ))}
          </div>
          <button onClick={handleVerifyMfa} className="w-full py-4 bg-indigo-600 text-white font-bold text-sm uppercase rounded-2xl">Validate Session</button>
        </div>
      </div>
    );
  }

  if (authState === 'PROFILE') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-2xl bg-white p-12 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in duration-500">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-2">Welcome Client</h2>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-10">Localization Preferences</p>
          <form onSubmit={handleProfileSubmit} className="space-y-8">
            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Legal Name</label>
                <input required className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Designation</label>
                <input required className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">City</label>
                <input required className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
              </div>
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Jurisdiction</label>
                <select className="w-full bg-transparent outline-none font-bold text-lg text-slate-800 cursor-pointer" value={formData.country} onChange={e => setFormData({...formData, country: e.target.value})}>
                  {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
              </div>
            </div>
            <button type="submit" className="w-full py-5 bg-indigo-600 text-white font-bold text-sm uppercase rounded-2xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Configure Cloud Storage</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="w-full max-w-2xl bg-white p-12 rounded-3xl shadow-xl border border-slate-100 animate-in slide-in-from-right-10 duration-500">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-xl">☁️</div>
          <div>
            <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Cloud Initialization</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Connect your Google Drive Database</p>
          </div>
        </div>

        <form onSubmit={handleCloudSubmit} className="space-y-8">
          <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100 space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Google Drive Folder/Resource Link</label>
              <input 
                required 
                type="url"
                placeholder="https://drive.google.com/drive/folders/..." 
                className="w-full p-4 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium text-sm text-slate-600" 
                value={formData.cloudDatabaseLink} 
                onChange={e => setFormData({...formData, cloudDatabaseLink: e.target.value})} 
              />
              <p className="text-[9px] text-slate-400 font-medium italic ml-1">* This folder will store your encrypted JSON database file.</p>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">New Database Filename</label>
              <div className="flex items-center gap-2">
                <input 
                  required 
                  placeholder="MyWealthDB" 
                  className="flex-1 p-4 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm text-slate-800" 
                  value={formData.cloudDatabaseName} 
                  onChange={e => setFormData({...formData, cloudDatabaseName: e.target.value})} 
                />
                <span className="text-xs font-bold text-slate-400">.json</span>
              </div>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={isVerifyingCloud}
            className={`w-full py-5 text-white font-bold text-sm uppercase rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3 ${isVerifyingCloud ? 'bg-slate-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}
          >
            {isVerifyingCloud ? (
              <>
                <span className="animate-spin text-lg">⚙️</span>
                Provisioning File...
              </>
            ) : 'Create Cloud Database'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const memberSelectorRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);

  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (memberSelectorRef.current && !memberSelectorRef.current.contains(event.target as Node)) {
        setShowMemberSelector(false);
      }
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const toggleMember = (id: string) => {
    let current = activeMemberIds.includes('all') ? [] : [...activeMemberIds];
    if (current.includes(id)) {
      current = current.filter(i => i !== id);
    } else {
      current.push(id);
    }
    setActiveMemberIds(current);
  };

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'transactions', label: 'Ledger', icon: '💸' },
    { id: 'accounts', label: 'Wealth', icon: '🏦' },
    { id: 'statements', label: 'P&L & Balance Sheet', icon: '📜' },
    { id: 'profile', label: 'Account', icon: '👤' },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 border-r border-slate-800 z-30 flex flex-col text-white">
        <div className="p-8">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <p className="text-xs font-medium text-slate-400 mt-1">Finance Suite</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}

          <div className="pt-10">
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase"
            >
              <span>🔄</span> Reset Workspace
            </button>
          </div>
        </nav>

        <div className="p-6 space-y-3">
           <div className="p-4 bg-slate-800 rounded-2xl border border-slate-700">
             <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">CLIENT ID</p>
             <p className="text-sm font-mono text-slate-300 truncate">{state.profile?.mobileNumber || 'OFFLINE'}</p>
           </div>
           {state.profile.cloudDatabaseName && (
             <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
               <div className="flex items-center gap-2 mb-1">
                 <span className="text-[10px]">☁️</span>
                 <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">Active Database</p>
               </div>
               <p className="text-[11px] font-bold text-indigo-200 truncate">{state.profile.cloudDatabaseName}.json</p>
             </div>
           )}
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto h-screen relative flex flex-col custom-scrollbar">
        {/* Header */}
        <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 py-4 z-40 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-6">
            <h2 className="text-sm font-bold text-slate-800 uppercase tracking-widest">
              {navItems.find(i => i.id === activeTab)?.label || activeTab}
            </h2>
            <button 
              onClick={handleSync}
              disabled={isSyncing}
              className={`flex items-center gap-2 px-6 py-2 rounded-full text-xs font-bold transition-all ${
                isSyncing 
                  ? 'bg-slate-100 text-slate-400' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-md shadow-indigo-200'
              }`}
            >
              <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
              {isSyncing ? 'Syncing...' : 'Sync Cloud'}
            </button>
          </div>

          <div className="flex items-center gap-5">
            <div className="flex items-center gap-1 bg-slate-100 p-1 border border-slate-200 rounded-full">
              <button 
                onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }}
                className={`px-5 py-1.5 rounded-full text-xs font-bold transition-all ${currentView === 'me' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
              > Me </button>
              <button 
                onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }}
                className={`px-5 py-1.5 rounded-full text-xs font-bold transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}
              > Family </button>
            </div>

            <div className="relative" ref={notificationsRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="relative p-2.5 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 transition-all active:scale-95 shadow-sm"
              >
                <span className="text-xl">🔔</span>
                {unreadCount > 0 && (
                  <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                    {unreadCount}
                  </span>
                )}
              </button>
              {showNotifications && (
                <div className="absolute right-0 mt-4 w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-xs font-bold text-slate-800 uppercase tracking-widest">Notifications</h4>
                    <button onClick={clearNotifications} className="text-[10px] font-bold text-indigo-600 hover:underline">Clear</button>
                  </div>
                  <div className="max-h-[32rem] overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-50' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-sm font-bold text-slate-800">{n.title}</p>
                          <span className="text-[10px] font-medium text-slate-400">{n.timestamp}</span>
                        </div>
                        <p className="text-xs text-slate-500 leading-relaxed">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-10 text-center text-slate-400 italic text-sm">No new alerts</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto w-full flex-1">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

