              </div>
            </div>

            <button type="submit" disabled={isVerifyingCloud} className={`w-full py-4 text-white font-bold text-sm uppercase rounded-2xl transition-all shadow-lg flex items-center justify-center gap-2 ${isVerifyingCloud ? 'bg-slate-400' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}>
              {isVerifyingCloud ? (<><span className="animate-spin">⚙️</span> Checking Cloud...</>) : 'Request Access'}
            </button>
          </form>

          <div className="mt-10 pt-8 border-t border-slate-100">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest text-center mb-4">Backup & Restore</p>
            <div className="flex gap-4">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex-1 py-3 px-4 bg-slate-50 border border-slate-200 text-slate-600 rounded-xl text-[10px] font-bold uppercase hover:bg-slate-100 transition-all flex items-center justify-center gap-2"
