            {isExistingUser ? 'Restore Data & Login' : 'Validate Session'}
          </button>
        </div>
      </div>
    );
  }

  if (authState === 'PROFILE') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-2xl bg-white p-12 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in duration-500">
