          <form onSubmit={handleProfileSubmit} className="space-y-8">
            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Legal Name</label>
                <input required placeholder="Full Name" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Designation</label>
                <input required placeholder="Profession" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">City</label>
                <input required placeholder="Current City" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
              </div>
              <div className="space-y-2 border-b border-slate-100 pb-3">
                <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Jurisdiction</label>
                <select className="w-full bg-transparent outline-none font-bold text-lg text-slate-800 cursor-pointer" value={formData.country} onChange={e => {
                  const country = countries.find(c => c.name === e.target.value);
                  setFormData({...formData, country: e.target.value, currency: country?.currency || 'USD'});
                }}>
                  {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
