                <div className="w-12 h-12 bg-slate-50 text-indigo-600 flex items-center justify-center font-bold text-lg rounded-xl border border-slate-100">{member.name.charAt(0)}</div>
                <div>
                  <p className="text-sm font-bold text-slate-800">{member.name}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{member.relation} • {member.mobileNumber}</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="flex flex-col items-end">
                  <span className="text-[9px] font-bold text-slate-400 uppercase mb-1">Sync</span>
                  <button onClick={() => toggleFamilyMemberTxPermission(member.id)} className={`relative inline-flex h-5 w-10 items-center rounded-full transition-colors ${member.canAddTransactions !== false ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                    <span className={`inline-block h-3 w-3 transform bg-white rounded-full transition-transform ${member.canAddTransactions !== false ? 'translate-x-6' : 'translate-x-1'}`} />
                  </button>
                </div>
                <button onClick={() => removeFamilyMember(member.id)} className="opacity-0 group-hover:opacity-100 p-2 text-rose-400 hover:bg-rose-50 rounded-lg transition-all text-sm"> 🗑️ </button>
              </div>
            </div>
          ))}
          {profile?.familyMembers.length === 0 && (
            <div className="col-span-full py-16 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
               <p className="text-sm text-slate-400 font-medium">No family members linked</p>
            </div>
          )}
        </div>

        {showAddMember && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
             <div className="bg-white w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in zoom-in duration-200">
               <h4 className="text-lg font-bold text-slate-800 mb-8 border-b border-slate-100 pb-4">Add Family Member</h4>
               <form onSubmit={handleAddMember} className="space-y-6">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Full Name</label>
                    <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.name} onChange={e => setNewMember({...newMember, name: e.target.value})} placeholder="Member Name" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Relation</label>
                    <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.relation} onChange={e => setNewMember({...newMember, relation: e.target.value})}>
                      <option>Spouse</option><option>Child</option><option>Parent</option><option>Sibling</option><option>Partner</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Mobile Number</label>
                    <input required type="tel" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.mobile} onChange={e => setNewMember({...newMember, mobile: e.target.value.replace(/\D/g, '')})} placeholder="Identification Key" />
                  </div>
                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => setShowAddMember(false)} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold text-xs rounded-xl">Cancel</button>
                    <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white font-bold text-xs rounded-xl shadow-lg shadow-indigo-100">Link Member</button>
                  </div>
               </form>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Profile;

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';

const countries = [
  { name: 'India', currency: 'INR' }, { name: 'United Kingdom', currency: 'GBP' }, { name: 'United States', currency: 'USD' },
  { name: 'Singapore', currency: 'SGD' }, { name: 'United Arab Emirates', currency: 'AED' }, { name: 'Japan', currency: 'JPY' }
];

const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet, loadStateFromCloud } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PROFILE'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [isVerifyingCloud, setIsVerifyingCloud] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    age: '',
    city: '',
    country: 'India',
    currency: 'INR',
    openingCash: '0'
  });

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) {
      setIsVerifyingCloud(true);
      const exists = await loadStateFromCloud(mobileNumber);
      setIsExistingUser(exists);
      setIsVerifyingCloud(false);
      setAuthState('MFA');
    }
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) {
      if (isExistingUser) setAuthenticated(true);
      else setAuthState('PROFILE');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Complete setup immediately - cloud sync can be configured in Profile later
    updateProfile({ 
      ...formData, 
      age: Number(formData.age), 
      mobileNumber, 
      isBoarded: true, 
      familyMembers: [],
      cloudDatabaseName: 'Default_Vault'
    });

    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });
    setAuthenticated(true);
  };

  if (authState === 'MOBILE') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-xl animate-in zoom-in duration-500 border border-slate-100">
          <div className="mb-10 text-center">
            <div className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center text-2xl font-black mx-auto mb-4">M</div>
            <h1 className="text-3xl font-black tracking-tight text-slate-800">MyFin</h1>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-2">Private Wealth Portal</p>
          </div>

          <form onSubmit={handleSendOtp} className="space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Mobile Number</label>
              <div className="relative border-b-2 border-slate-200 pb-3 focus-within:border-indigo-600 transition-colors">
                <span className="absolute left-0 text-slate-400 font-bold">+</span>
                <input required type="tel" placeholder="Enter Mobile Number" className="w-full pl-6 bg-transparent outline-none font-bold text-xl tracking-widest placeholder:text-slate-200" value={mobileNumber} onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))} />
              </div>
            </div>

            <button type="submit" disabled={isVerifyingCloud} className={`w-full py-4 text-white font-bold text-sm uppercase rounded-2xl transition-all shadow-lg flex items-center justify-center gap-2 ${isVerifyingCloud ? 'bg-slate-400' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}>
              {isVerifyingCloud ? (<><span className="animate-spin">⚙️</span> Authenticating...</>) : 'Request Access'}
            </button>
          </form>

          <p className="mt-8 text-[10px] text-slate-400 text-center font-medium leading-relaxed">
            Authorized personnel only. Data management and local restore options are available within the management portal after authentication.
          </p>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-xl animate-in fade-in slide-in-from-right-10 duration-500 border border-slate-100">
          <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-3">Security Check</h2>
          <p className="text-xs text-slate-500 font-medium leading-relaxed mb-10">Verification code sent to <span className="text-slate-800 font-bold">+{mobileNumber}</span></p>
          <div className="flex justify-between gap-3 mb-10">
            {otp.map((digit, i) => (
              <input key={i} id={`otp-${i}`} required type="number" className="w-full h-16 text-center text-3xl font-black bg-slate-50 border border-slate-200 rounded-2xl focus:border-indigo-600 focus:bg-white outline-none transition-all" value={digit} onChange={e => {
                const n = [...otp]; n[i] = e.target.value.slice(-1); setOtp(n);
                if (e.target.value && i < 3) document.getElementById(`otp-${i+1}`)?.focus();
              }} />
            ))}
          </div>
          <button onClick={handleVerifyMfa} className="w-full py-4 bg-indigo-600 text-white font-bold text-sm uppercase rounded-2xl">
            {isExistingUser ? 'Restore Data & Login' : 'Validate Session'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="w-full max-w-2xl bg-white p-12 rounded-3xl shadow-xl border border-slate-100 animate-in fade-in duration-500">
        <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-2">Welcome Client</h2>
        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-10">Localization Preferences</p>
        <form onSubmit={handleProfileSubmit} className="space-y-8">
          <div className="grid grid-cols-2 gap-8">
            <div className="space-y-2 border-b border-slate-100 pb-3">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Legal Name</label>
              <input required placeholder="Full Name" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
            </div>
            <div className="space-y-2 border-b border-slate-100 pb-3">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Designation</label>
              <input required placeholder="Profession" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-8">
            <div className="space-y-2 border-b border-slate-100 pb-3">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">City</label>
              <input required placeholder="Current City" className="w-full bg-transparent outline-none font-bold text-lg text-slate-800" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
            </div>
            <div className="space-y-2 border-b border-slate-100 pb-3">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Jurisdiction</label>
              <select className="w-full bg-transparent outline-none font-bold text-lg text-slate-800 cursor-pointer" value={formData.country} onChange={e => {
                const country = countries.find(c => c.name === e.target.value);
                setFormData({...formData, country: e.target.value, currency: country?.currency || 'USD'});
              }}>
                {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
              </select>
            </div>
          </div>
          <div className="space-y-2 border-b border-slate-100 pb-3">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Opening Cash Balance</label>
            <input type="number" step="any" placeholder="0.00" className="w-full bg-transparent outline-none font-black text-2xl text-indigo-600" value={formData.openingCash} onChange={e => setFormData({...formData, openingCash: e.target.value})} />
          </div>
          <button type="submit" className="w-full py-5 bg-indigo-600 text-white font-bold text-sm uppercase rounded-2xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Setup Financial Portal</button>
        </form>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission, importState } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
  const [editingCloudLabel, setEditingCloudLabel] = useState(false);
  const [cloudLabel, setCloudLabel] = useState(profile.cloudDatabaseName || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      addFamilyMember({
        id: Math.random().toString(36).substr(2, 9),
        name: newMember.name,
        relation: newMember.relation,
        mobileNumber: newMember.mobile,
        canAddTransactions: newMember.canAddTransactions
      });
      setNewMember({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
      setShowAddMember(false);
    }
  };

  const handleUpdateCloudLabel = () => {
    updateProfile({ ...profile, cloudDatabaseName: cloudLabel });
    setEditingCloudLabel(false);
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(state, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `myfin_backup_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (window.confirm("This will overwrite your current state with the imported backup. Continue?")) {
            importState(json);
          }
        } catch (err) {
          alert("Invalid backup file format.");
        }
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-40 bg-indigo-600 p-8 flex items-end relative overflow-hidden">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter select-none">MF</div>
           <div className="w-24 h-24 bg-white p-1 translate-y-12 z-10 shadow-xl rounded-2xl">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-4xl font-black text-indigo-600 rounded-xl">
                 {profile?.name?.charAt(0) || '?'}
               </div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight">{profile?.name}</h3>
              <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
            <div className="text-right">
               <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-1">Mobile</p>
               <p className="text-sm font-bold text-slate-600">+{profile?.mobileNumber}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6 p-6 bg-slate-50 border border-slate-100 rounded-2xl">
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">City</p><p className="text-sm font-bold text-slate-800">{profile?.city}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Country</p><p className="text-sm font-bold text-slate-800">{profile?.country}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Currency</p><p className="text-sm font-bold text-indigo-600">{profile?.currency}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Age</p><p className="text-sm font-bold text-slate-800">{profile?.age} Years</p></div>
          </div>
        </div>
      </div>

      {/* Cloud & Data Management Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div>
            <div className="flex items-center gap-3 mb-2">
              <h3 className="text-lg font-bold text-slate-800 tracking-tight">Cloud Connectivity</h3>
              <span className="text-[10px] bg-indigo-50 text-indigo-600 font-bold px-2 py-0.5 rounded">Supabase Enabled</span>
            </div>
            <p className="text-xs text-slate-400 font-medium mb-8">Manage your remote vault identity for real-time synchronization across devices.</p>

            <div className="space-y-4">
              <div className="p-4 bg-slate-50 border border-slate-100 rounded-2xl">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Vault Identifier</label>
                {editingCloudLabel ? (
                  <div className="flex gap-2">
                    <input 
                      autoFocus
                      className="flex-1 p-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm"
                      value={cloudLabel}
                      onChange={e => setCloudLabel(e.target.value)}
                    />
                    <button onClick={handleUpdateCloudLabel} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold shadow-md">Save</button>
                  </div>
                ) : (
                  <div className="flex justify-between items-center">
                    <p className="text-sm font-black text-slate-800">{profile.cloudDatabaseName || 'No Vault Label'}</p>
                    <button onClick={() => setEditingCloudLabel(true)} className="text-[10px] font-bold text-indigo-600 uppercase">Change</button>
                  </div>
                )}
              </div>
            </div>
          </div>
          <div className="mt-6 flex items-center gap-3 text-[10px] text-slate-400 font-medium italic bg-indigo-50/50 p-3 rounded-xl">
             <span>☁️</span> Your data is automatically synced to the Supabase cloud using your mobile number as the key.
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 tracking-tight mb-2">Data Management</h3>
          <p className="text-xs text-slate-400 font-medium mb-8">Backup your financial data to a local file or restore from a previous export.</p>

          <div className="flex flex-col gap-3">
            <button 
              onClick={handleExportData}
              className="w-full px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-2xl text-xs font-bold uppercase hover:bg-slate-50 transition-all shadow-sm flex items-center justify-between"
            >
              <span className="flex items-center gap-2"><span>💾</span> Local JSON Backup</span>
              <span className="text-[10px] text-slate-400">Export</span>
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full px-6 py-4 bg-indigo-50 border border-indigo-100 text-indigo-600 rounded-2xl text-xs font-bold uppercase hover:bg-indigo-100 transition-all shadow-sm flex items-center justify-between"
            >
              <span className="flex items-center gap-2"><span>📂</span> Restore from File</span>
              <span className="text-[10px] text-indigo-400 font-bold">Import</span>
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileImport} />
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-10">
          <div>
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Family Members</h3>
            <p className="text-xs text-slate-400 font-medium">Shared access and permissions</p>
          </div>
          <button onClick={() => setShowAddMember(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">+ Link Member</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
