             <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
               <div className="flex items-center gap-2 mb-1">
                 <span className="text-[10px]">☁️</span>
                 <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">Connected Vault</p>
               </div>
               <p className="text-[11px] font-bold text-indigo-200 truncate">{state.profile.cloudDatabaseName}</p>
             </div>
